INSERT INTO `directions` VALUES (1,'Терапия','terapiya','Первичный приём и лечение у терапевта','{\"banner\": \"images/hero-doctor.png\", \"general\": \"Терапевт — первый контакт пациента с клиникой: сбор жалоб, осмотр, направления на анализы и инструментальные методы, выписка справок, ведение хронических заболеваний и диспансеризация.\", \"when_list\": [\"ОРВИ, подъём температуры, слабость без ясного диагноза\", \"Хронические болезни: гипертония, ИБС, бронхит и др.\", \"Профилактический осмотр и чек-ап\", \"Нужны направления к узким специалистам\", \"Оформление справок для работы и учёбы — по правилам клиники\"], \"conclusion\": \"При острых состояниях врач определит срочность и необходимость госпитализации.\", \"treat_list\": [\"Приём и первичная диагностика\", \"Расшифровка анализов\", \"Диспансеризация\", \"Ведение хронических заболеваний\", \"Направления к профильным специалистам\"], \"when_subtitle\": \"Когда записаться к терапевту?\", \"treat_subtitle\": \"Чем помогает терапевт\"}','fa-stethoscope',NULL,NULL,'active',8,'2026-04-20 05:55:44','2026-04-20 11:17:13'),(2,'Кардиология','kardiologiya','Диагностика и лечение заболеваний сердца и сосудов','{\"banner\": \"images/hero-doctor.png\", \"general\": \"Кардиологическое направление объединяет приём кардиолога, функциональную диагностику и подбор терапии при гипертонии, ишемии, аритмиях и других состояниях. Мы ориентируемся на современные клинические рекомендации и сопровождаем пациента от первичной консультации до контрольных визитов.\", \"when_list\": [\"Повышенное давление, головокружения, отёки\", \"Боли или дискомфорт в груди, перебои в сердце\", \"Одышка при нагрузке, слабость\", \"Наследственная отягощённость по сердечно-сосудистым заболеваниям\", \"Подготовка к операции или спорту — чек-ап сердца\"], \"conclusion\": \"При острых болях в груди и выраженной одышке необходима неотложная помощь; в плановых случаях мы подберём обследование и лечение.\", \"treat_list\": [\"Консультации кардиолога\", \"ЭКГ и расшифровка\", \"Эхокардиография (УЗИ сердца)\", \"Холтеровское мониторирование и СМАД — по показаниям\", \"Коррекция терапии и диспансерное наблюдение\"], \"when_subtitle\": \"Когда обратиться к кардиологу?\", \"treat_subtitle\": \"Что входит в направление\"}','fa-heartbeat',NULL,NULL,'active',10,'2026-04-20 05:55:44','2026-04-20 11:17:13'),(3,'Неврология','nevrologiya','Диагностика и лечение заболеваний нервной системы','{\"banner\": \"images/hero-doctor.png\", \"general\": \"Неврологи занимаются головными болями, болями в спине и шее, нарушениями чувствительности, головокружениями, последствиями травм и инсультов в стадии реабилитации. При необходимости назначаются ЭЭГ, ЭНМГ и другие методы.\", \"when_list\": [\"Регулярные или сильные головные боли\", \"Боль, онемение в конечностях, шее, пояснице\", \"Головокружения, шум в ушах — после исключения срочной патологии\", \"Нарушения сна, вегетативные симптомы — по показаниям\", \"Направление после травмы или для динамического наблюдения\"], \"conclusion\": \"При внезапном слабости в конечностях, нарушении речи или сознания нужна скорая помощь.\", \"treat_list\": [\"Консультации невролога\", \"Лечение головных болей и болевого синдрома спины\", \"ЭЭГ и ЭНМГ — по назначению\", \"Блокады при болевом синдроме — по протоколу\", \"Рекомендации по режиму и терапии\"], \"when_subtitle\": \"Когда к неврологу?\", \"treat_subtitle\": \"Направление включает\"}','fa-brain',NULL,NULL,'active',12,'2026-04-20 05:55:44','2026-04-20 11:17:13'),(5,'Гинекология','ginekologiya','Женское здоровье, ведение беременности','{\"banner\": \"images/hero-doctor.png\", \"general\": \"Гинекология в «Маяк Здоровья» — это комплексный подход к женскому здоровью: от профилактики и планирования беременности до лечения воспалительных процессов и доброкачественных образований. Врачи ведут приём в комфортных кабинетах, при необходимости назначают УЗИ и лабораторную диагностику.\", \"when_list\": [\"Нарушения менструального цикла, болезненные месячные\", \"Планирование беременности, подготовка к зачатию\", \"Беременность: ведение и консультации\", \"Выделения, дискомфорт, боль внизу живота\", \"Профилактический осмотр раз в год\"], \"conclusion\": \"Не откладывайте визит при появлении симптомов — ранняя диагностика упрощает лечение и сохраняет репродуктивное здоровье.\", \"treat_list\": [\"Консультации и осмотры гинеколога\", \"УЗИ органов малого таза\", \"Ведение беременности\", \"Лечение воспалительных заболеваний\", \"Подбор контрацепции и реабилитация после родов\"], \"when_subtitle\": \"Когда записаться к гинекологу?\", \"treat_subtitle\": \"Чем мы можем помочь\"}','fa-user-doctor',NULL,NULL,'active',1,'2026-04-20 05:55:44','2026-04-20 11:17:13'),(9,'Проктология','proktologiya','Диагностика и лечение заболеваний прямой кишки','{\"banner\": \"images/promos/proctology-banner.jpg\", \"general\": \"Проктология — это раздел медицины, который занимается диагностикой и лечением заболеваний прямой кишки, анального канала и перианальной области. В клинике экспертной медицины «Маяк Здоровья» подготовлена вся необходимая база для консультаций и лечения пациентов: работает проктологический кабинет, есть собственная операционная с лазерным и радиоволновым оборудованием. Мы тщательно подходим к выбору сотрудников, поэтому наши проктологи — это врачи с многолетним практическим опытом, применяющие малоинвазивные методики для быстрого восстановления пациентов.\", \"when_list\": [\"Боль, зуд, жжение, отёчность в области ануса\", \"Выделение крови, гноя или слизи из прямой кишки\", \"Появление (выпадение) геморроидальных узлов\", \"Новообразования в перианальной зоне\", \"Чувство дискомфорта в области прямой кишки\", \"Запоры, поносы, боли в животе и его вздутие\"], \"conclusion\": \"Если у Вас появились такие симптомы, то вам необходима консультация специалиста проктолога. Своевременный осмотр избавит вас от сомнений и позволит подобрать эффективный и щадящий метод лечения.\", \"treat_list\": [\"Полное первичное обследование у проктолога\", \"Лечение острой и хронической анальной трещины\", \"Лечение хронического геморроя, лигирование латексными кольцами\", \"Удаление анальных папиллом, бахромок, кондилом\", \"Полипэктомия через аноскоп\", \"Удаление атером, липом, фибром перианальной области\", \"Иссечение интрасфинктерных свищей прямой кишки\"], \"when_subtitle\": \"Когда обратиться к проктологу?\", \"treat_subtitle\": \"Что мы лечим?\"}','fa-procedures',NULL,NULL,'active',3,'2026-04-20 05:55:44','2026-04-20 11:17:13'),(10,'Хирургия','hirurgiya','Амбулаторная и малоинвазивная хирургия','{\"banner\": \"images/hero-doctor.png\", \"general\": \"Хирургическое направление клиники ориентировано на амбулаторную помощь: малые операции, удаление доброкачественных новообразований кожи, вскрытие ограниченных гнойников, биопсии и послеоперационное наблюдение по протоколу.\", \"when_list\": [\"Новообразования кожи и подкожной клетчатки — оценка и удаление\", \"Повторяющиеся воспалительные очаги, подозрение на абсцесс\", \"Подготовка к малоинвазивному вмешательству\", \"Раны, швы, послеоперационный осмотр\", \"Направление от профильного специалиста\"], \"conclusion\": \"Объём вмешательства и анестезия согласуются на приёме; при противопоказаниях врач предложит альтернативу.\", \"treat_list\": [\"Консультация хирурга\", \"Малые хирургические операции\", \"Удаление новообразований кожи\", \"Вскрытие абсцессов — по показаниям\", \"Биопсия и послеоперационное наблюдение\"], \"when_subtitle\": \"Когда обратиться к хирургу?\", \"treat_subtitle\": \"Что мы делаем\"}','fa-syringe',NULL,NULL,'active',4,'2026-04-20 05:55:44','2026-04-20 11:17:13'),(11,'Эндокринология','endokrinologiya','Экспертная эндокринология – уникальное предложение в «Маяке здоровья»! Для идеальной работы эндокринной системы каждого пациента мы организовали консультации лучших эндокринологов Минска и уникальные услуги по лечению заболеваний эндокринной системы!','{\"faq\": [], \"general\": \"Эндокринология занимается гормональной регуляцией организма: щитовидная железа, поджелудочная железа, надпочечники, ожирение и нарушения обмена веществ. Врачи подбирают обследование (анализы, УЗИ щитовидной железы) и терапию с учётом вашего образа жизни и сопутствующих заболеваний.\", \"when_list\": [\"Подозрение на сахарный диабет или уже установленный диагноз\", \"Изменения веса, жажда, слабость, дрожь\", \"Узел или увеличение щитовидной железы\", \"Нарушения менструального цикла на фоне гормонов\", \"Планирование беременности при эндокринных заболеваниях\"], \"conclusion\": \"Контроль гормонов важен при хронических заболеваниях — регулярные визиты помогают избежать осложнений.\", \"treat_list\": [\"Консультации эндокринолога\", \"УЗИ щитовидной железы\", \"Назначение и интерпретация анализов на гормоны\", \"Ведение сахарного диабета и предиабета\", \"Коррекция веса и обмена веществ\"], \"when_subtitle\": \"Когда обратиться к эндокринологу?\", \"treat_subtitle\": \"Направление включает\"}','fa-pills',NULL,NULL,'active',0,'2026-04-20 05:55:44','2026-04-21 10:48:09'),(12,'Урология','urologiya','Мужское здоровье и лечение мочеполовой системы','{\"banner\": \"images/hero-doctor.png\", \"general\": \"Урология охватывает заболевания почек, мочевого пузыря, предстательной железы и мужских половых путей. В клинике проводятся консультации, УЗИ, назначается терапия и профилактика обострений.\", \"when_list\": [\"Боль или жжение при мочеиспускании\", \"Частые позывы, недержание, слабая струя\", \"Боль в пояснице, подозрение на камни\", \"Симптомы простатита, ИППП — обследование и лечение\", \"Профилактический осмотр мужчин после 40 лет\"], \"conclusion\": \"Не откладывайте визит при крови в моче или сильной боли — это может требовать срочной помощи.\", \"treat_list\": [\"Приём уролога\", \"УЗИ почек и мочевого пузыря\", \"УЗИ предстательной железы\", \"Лечение ИППП и простатита — по протоколу\", \"Уродинамика и другое — по показаниям\"], \"when_subtitle\": \"Когда обратиться к урологу?\", \"treat_subtitle\": \"Услуги\"}','fa-user-doctor',NULL,NULL,'active',13,'2026-04-20 05:55:44','2026-04-20 11:17:13'),(15,'Гастроэнтерология','gastroenterologiya','Лечение заболеваний желудочно-кишечного тракта','{\"banner\": \"images/hero-doctor.png\", \"general\": \"Гастроэнтерологи клиники занимаются диагностикой и лечением заболеваний пищевода, желудка, кишечника, печени и желчевыводящих путей. При необходимости назначаются эндоскопические исследования, УЗИ, анализы и индивидуальная схема лечения.\", \"when_list\": [\"Изжога, отрыжка, тяжесть после еды\", \"Боли в животе, вздутие, нарушения стула\", \"Потеря веса без видимой причины\", \"Подготовка к ФГДС/колоноскопии по направлению\", \"Хронические гастрит, ЯБ, СРК — наблюдение\"], \"conclusion\": \"Своевременная диагностика ЖКТ помогает избежать осложнений; не занимайтесь самолечением при стойких симптомах.\", \"treat_list\": [\"Приём гастроэнтеролога и разбор анализов\", \"Гастроскопия и колоноскопия — по показаниям\", \"УЗИ органов брюшной полости\", \"Лечение заболеваний ЖКТ и дыхательный тест на H. pylori\", \"Рекомендации по питанию и диспансеризация\"], \"when_subtitle\": \"Когда нужен гастроэнтеролог?\", \"treat_subtitle\": \"Услуги направления\"}','fa-utensils',NULL,NULL,'active',11,'2026-04-20 05:55:44','2026-04-20 11:17:13'),(16,'УЗИ','uzi','Ультразвуковая диагностика всех органов','{\"banner\": \"images/hero-doctor.png\", \"general\": \"Ультразвуковое исследование — безопасный и информативный метод визуализации органов и сосудов. В клинике выполняется широкий спектр УЗИ: брюшная полость, малый таз, щитовидная железа, сосуды, сердце, молочные железы и др. Аппараты экспертного класса и врачи с большим опытом обеспечивают точность заключения.\", \"when_list\": [\"Назначение врача для уточнения диагноза\", \"Профилактика и диспансеризация\", \"Контроль при хронических заболеваниях\", \"Беременность: скрининги по срокам\", \"Оценка состояния органов после перенесённых заболеваний\"], \"conclusion\": \"Подготовка к отдельным видам УЗИ может отличаться — уточняйте у администратора или врача при записи.\", \"treat_list\": [\"УЗИ органов брюшной полости и почек\", \"УЗИ малого таза (трансабдоминально / трансвагинально)\", \"УЗИ щитовидной железы и лимфоузлов\", \"УЗИ сосудов (БЦА, вен и артерий конечностей)\", \"Эхокардиография и УЗИ мягких тканей\"], \"when_subtitle\": \"Когда нужно УЗИ?\", \"treat_subtitle\": \"Основные направления УЗИ\"}','fa-wave-square',NULL,NULL,'active',6,'2026-04-20 05:55:44','2026-04-20 11:17:13'),(18,'Функциональная диагностика','funkcionalnaya-diagnostika','ЭКГ, холтер, ЭЭГ, спирометрия','{\"banner\": \"images/hero-doctor.png\", \"general\": \"Функциональная диагностика помогает оценить работу сердца, сосудов головного мозга, лёгких и периферической нервной системы без операций. Исследования назначаются лечащим врачом и выполняются на сертифицированном оборудовании.\", \"when_list\": [\"Жалобы на сердце, давление, головокружения\", \"Подготовка к операции или контроль терапии\", \"Подозрение на нарушения ритма — Холтер\", \"Суточное АД — СМАД\", \"Одышка, кашель — спирометрия; судороги, головные боли — ЭЭГ/ЭНМГ по назначению\"], \"conclusion\": \"Расшифровку и дальнейшую тактику даёт ваш лечащий врач; часть исследований требует отмены препаратов — уточняйте при записи.\", \"treat_list\": [\"ЭКГ\", \"Суточное мониторирование ЭКГ (Холтер)\", \"СМАД\", \"Спирометрия\", \"ЭЭГ и ЭНМГ — по показаниям\"], \"when_subtitle\": \"Когда назначают обследования?\", \"treat_subtitle\": \"Исследования\"}','fa-heart-pulse',NULL,NULL,'active',7,'2026-04-20 05:55:44','2026-04-20 11:17:13'),(21,'Лазерная гинекология','lazernaya-ginekologiya','Современные лазерные методики в гинекологии','{\"banner\": \"images/hero-doctor.png\", \"general\": \"Лазерные технологии в гинекологии позволяют щадяще лечить патологии шейки матки и слизистой с минимальным периодом восстановления. Процедуры проводятся после очной консультации и при наличии показаний по результатам обследования.\", \"when_list\": [\"Эрозия и другие изменения эпителия шейки матки — по заключению врача\", \"Папилломавирусная инфекция, дисплазии — в рамках тактики лечения\", \"Потребность в малоинвазивной коррекции после консультации\", \"Реабилитация после диагностических процедур — по назначению\", \"Индивидуальный план после кольпоскопии и анализов\"], \"conclusion\": \"Объём и возможность лазерной методики определяет гинеколог после осмотра и анализов; самолечение недопустимо.\", \"treat_list\": [\"Консультация по лазерным методикам\", \"Лазерная коррекция патологий шейки матки\", \"Лазерное лечение эрозии\", \"Фракционный лазер в гинекологии\", \"Лазерная вапоризация — по показаниям\"], \"when_subtitle\": \"Когда рассматривают лазерное лечение?\", \"treat_subtitle\": \"Услуги направления\"}','fa-wand-magic-sparkles',NULL,NULL,'active',2,'2026-04-20 06:45:38','2026-04-20 11:17:13'),(22,'Лазерная хирургия','lazernaya-hirurgiya','Лазерная хирургия при малоинвазивных операциях','{\"banner\": \"images/hero-doctor.png\", \"general\": \"Лазерная хирургия применяется для точного воздействия на ткани с меньшим кровотечением и контролируемой глубиной. Подходит для ряда доброкачественных образований и поверхностных патологий — после очной консультации и оценки анестезиологического риска.\", \"when_list\": [\"Удаление новообразований кожи и слизистых — по заключению\", \"Лазерная коагуляция сосудистых изменений\", \"Вросший ноготь и другие локальные процессы — по тактике врача\", \"Реабилитация после процедуры по индивидуальному плану\", \"Повторный осмотр и контроль заживления\"], \"conclusion\": \"Противопоказания и объём процедуры определяет хирург; часть случаев требует предварительных анализов.\", \"treat_list\": [\"Консультация лазерного хирурга\", \"Лазерное удаление новообразований\", \"Лазерная вапоризация тканей\", \"Лазерная коагуляция\", \"Лазерное лечение вросшего ногтя\"], \"when_subtitle\": \"Когда показано лазерное лечение?\", \"treat_subtitle\": \"Услуги\"}','fa-wand-magic-sparkles',NULL,NULL,'active',5,'2026-04-20 06:45:38','2026-04-20 11:17:13'),(23,'Флебология','flebologiya','Диагностика и лечение заболеваний вен','{\"banner\": \"images/hero-doctor.png\", \"general\": \"Флебология решает проблемы венозного оттока: варикоз, тяжесть и отёки ног, сосудистые «звёздочки», трофические изменения. Диагностика УЗИ вен дополняет клинический осмотр и помогает выбрать консервативное или малоинвазивное лечение.\", \"when_list\": [\"Видимые расширенные вены, отёки к вечеру\", \"Боль, судороги и тяжесть в ногах\", \"После беременности или длительной «стоячей» работы\", \"Подготовка к операции на венах\", \"Профилактика тромботических осложнений — по назначению врача\"], \"conclusion\": \"Тактика лечения индивидуальна: от компрессии и медикаментов до склеротерапии и лазерной коагуляции.\", \"treat_list\": [\"Приём флеболога\", \"УЗИ вен нижних конечностей\", \"Консервативное лечение варикоза\", \"Склеротерапия — по показаниям\", \"Лазерная коагуляция вен\"], \"when_subtitle\": \"Когда к флебологу?\", \"treat_subtitle\": \"Услуги направления\"}','fa-hand-holding-medical',NULL,NULL,'active',9,'2026-04-20 06:45:38','2026-04-20 11:17:13'),(24,'Нефрология','nefrologiya','Специализированная помощь при заболеваниях почек','{\"banner\": \"images/hero-doctor.png\", \"general\": \"Нефролог занимается хронической болезнью почек, гипертонией почечного генеза, отёками и нарушениями анализов мочи. Лечение строится на контроле давления, диеты, коррекции метаболических нарушений и своевременной коррекции терапии.\", \"when_list\": [\"Отёки, снижение диуреза, изменения цвета мочи\", \"Повышенный креатинин, белок в моче по анализам\", \"Хроническая болезнь почек — наблюдение\", \"Артериальная гипертензия с поражением почек\", \"Подбор терапии при сочетании заболеваний\"], \"conclusion\": \"Регулярный контроль анализов и АД замедляет прогрессирование ХБП.\", \"treat_list\": [\"Консультации нефролога\", \"Диагностика заболеваний почек\", \"Лечение пиелонефрита — по схеме\", \"Наблюдение при ХБП\", \"Подбор терапии при почечной недостаточности\"], \"when_subtitle\": \"Когда к нефрологу?\", \"treat_subtitle\": \"Что мы делаем\"}','fa-vial',NULL,NULL,'active',14,'2026-04-20 06:45:38','2026-04-20 11:17:13'),(25,'Онкология','onkologiya','Ранняя диагностика и сопровождение онкологических пациентов','{\"banner\": \"images/hero-doctor.png\", \"general\": \"Онкологическое направление включает консультации, скрининг, интерпретацию анализов и инструментальных исследований, сопровождение после лечения. Тактика всегда мультидисциплинарная и согласуется с профильными специалистами.\", \"when_list\": [\"Подозрительные узлы, длительно незаживающие изменения кожи\", \"Потеря веса, слабость без причины\", \"Результаты скрининга, требующие уточнения\", \"Наблюдение после операции или химиотерапии\", \"Семейная отягощённость — профилактическая консультация\"], \"conclusion\": \"Ранняя диагностика улучшает прогноз; не игнорируйте рекомендации по обследованию.\", \"treat_list\": [\"Консультация онколога\", \"Онкоскрининг\", \"Биопсия и гистология — по показаниям\", \"Наблюдение после лечения\", \"Паллиативная поддержка — по запросу и протоколу\"], \"when_subtitle\": \"Когда записаться к онкологу?\", \"treat_subtitle\": \"Направление\"}','fa-ribbon',NULL,NULL,'active',15,'2026-04-20 06:45:38','2026-04-20 11:17:13'),(26,'Маммология','mammologiya','Профилактика и диагностика заболеваний молочных желёз','{\"banner\": \"images/hero-doctor.png\", \"general\": \"Маммология направлена на профилактику рака молочной железы и лечение доброкачественной патологии. Сочетание осмотра, УЗИ и при необходимости маммографии позволяет выявить изменения на ранней стадии.\", \"when_list\": [\"Уплотнение, боль или выделения из соска\", \"Профилактика раз в год после 40 лет — по рекомендациям\", \"Наблюдение при мастопатии и кистах\", \"Семейная история онкологии молочной железы\", \"Подготовка к беременности и лактации — консультация\"], \"conclusion\": \"Самообследование не заменяет визит к врачу; при любых изменениях лучше уточнить диагноз.\", \"treat_list\": [\"Приём маммолога\", \"УЗИ молочных желёз\", \"Маммография — по показаниям и возрасту\", \"Пункционная биопсия — по направлению\", \"Наблюдение при доброкачественной патологии\"], \"when_subtitle\": \"Когда к маммологу?\", \"treat_subtitle\": \"Услуги\"}','fa-heart',NULL,NULL,'active',16,'2026-04-20 06:45:38','2026-04-20 11:17:13'),(27,'Диетология','dietologiya','Индивидуальный подбор питания и коррекция веса','{\"banner\": \"images/hero-doctor.png\", \"general\": \"Диетолог помогает при избыточном и недостаточном весе, сахарном диабете, заболеваниях печени и ЖКТ, при беременности и спортивных нагрузках. План питания строится с учётом анализов и образа жизни.\", \"when_list\": [\"Лишний вес или резкая потеря веса\", \"Сахарный диабет, метаболический синдром\", \"Беременность и лактация — коррекция рациона\", \"Заболевания ЖКТ с диетотерапией\", \"Подготовка к марафону или восстановление после болезни\"], \"conclusion\": \"Устойчивый результат даёт сочетание питания, режима и при необходимости лекарственной терапии по назначению врача.\", \"treat_list\": [\"Консультации диетолога\", \"Подбор рациона при заболеваниях\", \"Коррекция веса\", \"Нутритивная поддержка\", \"Составление индивидуального меню\"], \"when_subtitle\": \"Когда к диетологу?\", \"treat_subtitle\": \"Что входит\"}','fa-utensils',NULL,NULL,'active',17,'2026-04-20 06:45:38','2026-04-20 11:17:13'),(28,'Психология','psihologiya','Консультации психолога, диагностика и поддержка','{\"banner\": \"images/hero-doctor.png\", \"general\": \"Психологическая помощь в клинике — это конфиденциальные беседы, диагностика эмоционального состояния, поддержка при стрессе, утрате, конфликтах и адаптации к болезни. Формат и кратность встреч согласуются с пациентом.\", \"when_list\": [\"Длительный стресс, тревога, раздражительность\", \"Трудности в отношениях и на работе\", \"Поддержка при хроническом заболевании\", \"Детско-подростковые вопросы — по запросу родителей\", \"Желание лучше понять себя и свои реакции\"], \"conclusion\": \"Психолог не заменяет психиатра при тяжёлых расстройствах; при необходимости будет рекомендован коллега.\", \"treat_list\": [\"Индивидуальные консультации\", \"Психодиагностика\", \"Семейная психология\", \"Детская психология\", \"Работа со стрессом и тревогой\"], \"when_subtitle\": \"Когда к психологу?\", \"treat_subtitle\": \"Форматы работы\"}','fa-head-side-virus',NULL,NULL,'active',18,'2026-04-20 06:45:38','2026-04-20 11:17:13'),(29,'Психотерапия','psihoterapiya','Психотерапевтическая помощь при тревоге и депрессии','{\"banner\": \"images/hero-doctor.png\", \"general\": \"Психотерапия — структурированная работа с доказательными методиками (в том числе КПТ) при депрессии, тревожных расстройствах, панических атаках и психосоматических реакциях. Курс согласуется с врачом и длится от нескольких встреч до длительной терапии.\", \"when_list\": [\"Депрессия, апатия, потеря интереса к жизни\", \"Панические атаки, навязчивые мысли\", \"Тревога, которая мешает работать и отдыхать\", \"Психосоматика — после исключения соматики\", \"Кризисные ситуации, утрата\"], \"conclusion\": \"При суицидальных мыслях или угрозе себе и окружающим необходима неотложная помощь.\", \"treat_list\": [\"Приём психотерапевта\", \"Когнитивно-поведенческая терапия\", \"Работа с депрессией и тревогой\", \"Кризисная психотерапия\", \"Групповая терапия — по расписанию клиники\"], \"when_subtitle\": \"Когда к психотерапевту?\", \"treat_subtitle\": \"Услуги\"}','fa-comments',NULL,NULL,'active',19,'2026-04-20 06:45:38','2026-04-20 11:17:13');
