INSERT INTO `doctors` VALUES (16,24,'Макеева','Алеся','Викторовна','makeeva-alesya-viktorovna','first','Кандидат медицинских наук',22,2004,'both','images/doctors/01KPS03MEQNAGFV15HWSAQ6DCP.png','Алеся Викторовна — врач ультразвуковой диагностики первой квалификационной категории с 22-летним стажем работы. В медицинском центре «Маяк Здоровья» выполняет широкий спектр ультразвуковых исследований: УЗИ органов брюшной полости, сосудов (БЦА, ТКДС, артерии и вены конечностей), щитовидной железы, молочных желез, почек, суставов и мягких тканей.',5.00,'[{\"type\": \"experience\", \"title\": \"Врач-гастроэнтеролог\", \"period\": \"Август 2004 — ноябрь 2004\", \"institution\": \"ГУ «Борисовское территориальное медицинское объединение»\"}, {\"type\": \"experience\", \"title\": \"Заведующий приёмным отделением\", \"period\": \"Ноябрь 2004 — декабрь 2006\", \"institution\": \"ГУ «Борисовское территориальное медицинское объединение»\"}, {\"type\": \"experience\", \"title\": \"Заместитель главного врача по медицинской части\", \"period\": \"Декабрь 2006 — май 2007\", \"institution\": \"ГУ «Борисовское территориальное медицинское объединение»\"}, {\"type\": \"experience\", \"title\": \"Врач ультразвуковой диагностики\", \"period\": \"Май 2007 — ноябрь 2007\", \"institution\": \"УЗ «Борисовская центральная районная больница»\"}, {\"type\": \"experience\", \"title\": \"Заведующий\", \"period\": \"Ноябрь 2007 — декабрь 2015\", \"institution\": \"УЗ «Борисовская больница № 2»\"}, {\"type\": \"experience\", \"title\": \"Врач ультразвуковой диагностики\", \"period\": \"Декабрь 2015 — март 2020\", \"institution\": \"УЗ «Борисовская центральная районная больница»\"}, {\"type\": \"experience\", \"title\": \"Врач ультразвуковой диагностики\", \"period\": \"Апрель 2020 — июнь 2021\", \"institution\": \"ООО «ЛаВита-центр»\"}, {\"type\": \"experience\", \"title\": \"Врач ультразвуковой диагностики, заместитель директора по медицинской части\", \"period\": \"Июль 2021 — август 2022\", \"institution\": \"ООО «Клиника в Уручье»\"}, {\"type\": \"experience\", \"title\": \"Врач ультразвуковой диагностики\", \"period\": \"Сентябрь 2022 — март 2023\", \"institution\": \"ООО «Центр магнитно-резонансной томографии Ортоклиник»\"}, {\"type\": \"experience\", \"title\": \"Врач ультразвуковой диагностики\", \"period\": \"Апрель 2023 — апрель 2025\", \"institution\": \"ГУ «Республиканский научно-практический центр неврологии и нейрохирургии»\"}, {\"type\": \"experience\", \"title\": \"Врач ультразвуковой диагностики\", \"period\": \"Апрель 2025 — н.в.\", \"institution\": \"Медицинский центр «Маяк здоровья» ООО «ЗАРГА Медика»\"}, {\"type\": \"education\", \"title\": \"Интернатура «Терапия»\", \"period\": \"2003–2004\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"ПК «Клиническая артрология»\", \"period\": \"2006\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"ППГ «Ультразвуковая диагностика»\", \"period\": \"2007\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"ППГ «Организация здравоохранения»\", \"period\": \"2010\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"ПК «Эхокардиография в диагностике приобретённых пороков сердца, болезней эндокарда и перикарда»\", \"period\": \"2012\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"ПК «Радиационная безопасность»\", \"period\": \"2013\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"ПК «Основы эхокардиографии»\", \"period\": \"2013\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"ПК «Ультразвуковая диагностика патологии сосудов нижних конечностей»\", \"period\": \"2017\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Ординатура «Ультразвуковая диагностика»\", \"period\": \"2017–2020\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"ПК «Основы управления здравоохранением в Республике Беларусь»\", \"period\": \"2018\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"ПК «Медицинская информатика и компьютерные технологии»\", \"period\": \"2018\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"ПК «Ультразвуковое исследование периферических сосудов»\", \"period\": \"2022\", \"institution\": \"\"}]','active',0,'2026-04-20 07:08:48','2026-05-01 08:51:42'),(28,24,'Бегун','Игорь','Васильевич','begun-igor-vasilevich','highest',NULL,40,1986,'both','images/doctors/01KPRZTFF9A97Z4H6AYK2C2MMW.png','Игорь Васильевич Бегун — врач ультразвуковой диагностики высшей квалификационной категории, кандидат медицинских наук, доцент, со стажем более 39 лет. Обладает многолетним опытом работы в сфере функциональной и ультразвуковой диагностики, в том числе на руководящих должностях. В медицинском центре «Маяк Здоровья» ведет прием как врач УЗИ, сочетая глубокую клиническую подготовку, большой практический опыт и постоянное профессиональное развитие.',0.00,'[{\"type\": \"experience\", \"title\": \"Младший научный сотрудник, старший лаборант\", \"period\": \"1986 - 1989\", \"institution\": \"Минский Ордена Трудового Красного знамени государственный медицинский институт\"}, {\"type\": \"experience\", \"title\": \"Врач отделения функциональной диагностики\", \"period\": \"1989 - 1994\", \"institution\": \"Минский диагностический центр\"}, {\"type\": \"experience\", \"title\": \"Врач ультразвуковой диагностики (заведующий) отделения функциональной диагностики\", \"period\": \"1994 - н.в.\", \"institution\": \"7-ая городская клиническая больница\"}, {\"type\": \"experience\", \"title\": \"Врач ультразвуковой диагностики\", \"period\": \"Июль 2025 - н.в.\", \"institution\": \"Медицинский центр «Маяк здоровья»\"}, {\"type\": \"education\", \"title\": \"Интернатура «Педиатрия»\", \"period\": \"Ноябрь 2006 - октябрь 2007\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"ППГ «Лучевая диагностика»\", \"period\": \"2009\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Конференция «Актуальные вопросы детской трансплантологии»\", \"period\": \"2010\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"ПК «Интервенционная радиология»\", \"period\": \"2011\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Конференция «Высокотехнологичные методы оказания медицинской помощи в педиатрии»\", \"period\": \"2012\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Конференция «Современные медицинские технологии в решении проблем демографической безопасности»\", \"period\": \"2012\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Конференция «Ультразвуковая диагностика в онкологии»\", \"period\": \"2013\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"ППГ «Ультразвуковая диагностика»\", \"period\": \"2014\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Семинар «Ультразвук»\", \"period\": \"2015\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"ПК «Ультразвуковая диагностика патологии внутренних органов»\", \"period\": \"2017\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Семинар «Ультразвук»\", \"period\": \"2017\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Конференция «Актуальные вопросы ультразвуковой диагностики в педиатрии»\", \"period\": \"2018\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Семинар «Новые технологии в ультразвуковой диагностике»\", \"period\": \"2018\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Семинар «Ультразвук»\", \"period\": \"2018\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"ПК «Клиническая трансторакальная эхокардиография»\", \"period\": \"2019\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"ПК «Ультразвук»\", \"period\": \"2019\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Конференция «Актуальные вопросы детской онкологии, гематологии и иммунологии»\", \"period\": \"2019\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"ПК «Правовое обеспечение деятельности по охране труда в организации»\", \"period\": \"2019\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Семинар «Новообразования кожи у детей и молодых взрослых»\", \"period\": \"2021\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Конференция «Актуальные вопросы детской онкологии, гематологии и иммунологии»\", \"period\": \"2021\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Конференция «Лучевая диагностика в клинической практике»\", \"period\": \"2023\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Конференция «Актуальные вопросы функциональной диагностики»\", \"period\": \"2023\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"ПК «Ультразвуковая диагностика патологии органов пищеварения»\", \"period\": \"2024\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Конференция «Мышечно-скелетная радиология: мультимодальный и мультидисциплинарный подход»\", \"period\": \"2024\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Конференция «Актуальные вопросы детской онкологии, гематологии и иммунологии»\", \"period\": \"2024\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"ПК «Миниинвазивные вмешательства под контролем ультразвука и рентгентелевидения»\", \"period\": \"2025\", \"institution\": \"\"}]','active',0,'2026-04-21 18:35:22','2026-04-22 06:54:45'),(29,23,'Никонович','Вадим','Васильевич','nikonovich','first',NULL,10,2016,'adults','images/doctors/01KPT1ZHP5F3KB9HHBWR9F27GY.png','Вадим Васильевич Никонович — врач-психотерапевт с первой квалификационной категорией и стажем работы 10 лет. Специализируется на когнитивно-поведенческой терапии, помогает при тревожных и навязчивых расстройствах, РПП, социальных фобиях, депрессии, прокрастинации и проблемах в отношениях. Также проводит семейное консультирование.',0.00,'[{\"type\": \"experience\", \"title\": \"\", \"period\": \"2012-2014гг.\", \"institution\": \"УЗ « Городской клинический психиатрический диспансер»\"}, {\"type\": \"experience\", \"title\": \"\", \"period\": \"2014-2017 гг.\", \"institution\": \"УЗ «Городской клинический наркологический диспансер»\"}, {\"type\": \"education\", \"title\": \"Окончил  лечебно - профилактическое дело.\", \"period\": \"2005 г.\", \"institution\": \"Гомельский государственный медицинский университет\"}, {\"type\": \"education\", \"title\": \"Интегративная терапия тревожно-фобических и депрессивных расстройств\", \"period\": \"2016 г.\", \"institution\": \"БелМАПО\"}]','active',0,'2026-04-22 04:37:54','2026-04-22 04:40:44'),(30,23,'Демко ','Дмитрий ','Федорович','demko','first',NULL,27,1999,'adults','images/doctors/01KPT2MY9W4AA1RQ34BFPHBACD.png','Дмитрий Федорович Демко — врач-психотерапевт с первой квалификационной категорией. Проводит консультации, помогает при социальных фобиях, прокрастинации, депрессии, проблемах во взаимоотношениях, занимается семейным консультированием. Имеет многолетний опыт и регулярно повышает квалификацию в области психотерапии, психиатрии и психосоматических расстройств.\n\nОбразование, практика\n1995 г. — Белорусский государственный медицинский университет\nКурсы повышения квалификации\n«Избранные вопросы психотерапии».\n«Психиатрия».\n«Диагностика и лечение тревожных расстройств».\n«Психотерапия психосоматических расстройств».\n«Диагностика и лечение тревожных расстройств».\n«Краткосрочные методы психотерапии».\n«Новое в диагностике и лечении психических и поведенческих расстройств».\n«Психосоматические заболевания и расстройства».\nДополнительные сведения\nIII съезд психиатров РБ, «Психиатрия и современное общество».\n\nРНПС «Краткосрочные методы психотерапии», ГУ «РНПЦ ПЗ».\n\nМНПК «Современный взгляд на проблемы когнитивных нарушений».\n\nСеминар «Центр экспертиз и испытаний в здравоохранении», Good Clinical Practice (GCP)',0.00,'[{\"type\": \"education\", \"title\": \"Психотерапия\", \"period\": \"1995 г.\", \"institution\": \"Белорусский государственный медицинский университет\"}]','active',0,'2026-04-22 04:49:35','2026-04-22 04:49:35'),(31,3,'Линник','Ольга','Вячеславовна','linnik-olga-vyacheslavovna','highest',NULL,10,2016,'both','images/doctors/01KPT99VEKB81V9JDGSQT70X7D.png','Ольга Вячеславовна Линник — врач-невролог высшей квалификационной категории со стажем 10 лет. В медицинском центре «Маяк Здоровья» ведет консультативный прием и выполняет лечебные блокады при заболеваниях нервной системы. Является членом Белорусского общества неврологов и Европейской академии неврологии (EAN), регулярно участвует в республиканских и международных научно-практических конференциях.',0.00,'[{\"type\": \"experience\", \"title\": \"Прохождение интернатуры\", \"period\": \"2011 - 2012\", \"institution\": \"ГУ «РНПЦ Неврологии и нейрохирургии»\"}, {\"type\": \"education\", \"title\": \"\", \"period\": \"2005 - 2011\", \"institution\": \"Белорусский государственный медицинский университет\"}, {\"type\": \"education\", \"title\": \"Современные технологии диагностики и лечения заболеваний нервной системы\", \"period\": \"2014\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Клиническая фармакология и рациональная фармакотерапия\", \"period\": \"\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Выступала с докладом на международном симпозиуме «Нейромышечные заболевания. От теории к клинической практике»\", \"period\": \"\", \"institution\": \"г. Краков, Польша\"}, {\"type\": \"education\", \"title\": \"Проходила обучение на Весенней школе для молодых неврологов, организованной Европейской федерацией неврологических сообществ\", \"period\": \"\", \"institution\": \"Чешская Республика\"}]','active',0,'2026-04-22 04:50:21','2026-04-22 06:45:52'),(32,2,' Бранковская','Елена','Юрьевна','brankovskaya-elena-yurevna','highest',NULL,10,2016,'both','images/doctors/01KPT65PKTV2XMAVM4AX2X8PN6.png','Елена Юрьевна Бранковская — врач-кардиолог высшей квалификационной категории, кандидат медицинских наук, со стажем 10 лет. Специализируется на профилактике, диагностике и лечении артериальной гипертензии, ишемической болезни сердца, нарушений ритма и проводимости, сердечной недостаточности. Сочетает клиническую практику, научную деятельность и современный подход к кардиологической помощи.',0.00,'[{\"type\": \"experience\", \"title\": \"Врач-интерн по специальности «Терапия»\", \"period\": \"2012\", \"institution\": \"Белорусская медицинская академия последипломного образования\"}, {\"type\": \"experience\", \"title\": \"Клинический ординатор по специальности «Кардиология»\", \"period\": \"2015 - 2018\", \"institution\": \"Белорусский государственный медицинский университет, кафедра кардиологии и внутренних болезней\"}, {\"type\": \"experience\", \"title\": \"Аспирант по специальности «Кардиология»\", \"period\": \"2017 – 2022\", \"institution\": \"Белорусский государственный медицинский университет, кафедра кардиологии и внутренних болезней\"}, {\"type\": \"education\", \"title\": \"Белорусский государственный медицинский университет, специальность «Лечебное дело»\", \"period\": \"\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Интернатура по специальности «Терапия»\", \"period\": \"2012\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Курсы повышения квалификации на базе Белорусской медицинской академии постдипломного образования «Клиническая кардиология»\", \"period\": \"2014\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Курсы повышения квалификации на базе Белорусской медицинской академии постдипломного образования «Медицинская экспертиза с основами реабилитации при основной инвалидизирующей патологии»\", \"period\": \"2018\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Обучение в клинической ординатуре по специальности «Кардиология» на кафедре кардиологии и внутренних болезней Белорусского государственного медицинского университета\", \"period\": \"2015 - 2018\", \"institution\": \"\"}]','active',0,'2026-04-22 05:51:10','2026-04-22 06:09:02'),(33,1,'Столярова','Татьяна','Игоревна','stolyarova-tatyana-igorevna','first',NULL,18,2006,'both','images/doctors/01KPTAHG2KNJRKFM0SJXBYP1W5.png','Татьяна Игоревна Столярова — врач-терапевт первой квалификационной категории со стажем 18 лет. В медицинском центре «Маяк Здоровья» занимается диагностикой, лечением и профилактикой широкого спектра терапевтических заболеваний: анемии, остеохондроза, заболеваний суставов, сахарного диабета 2 типа, сердечно-сосудистой патологии, заболеваний органов пищеварения и дыхательной системы.',0.00,'[{\"type\": \"experience\", \"title\": \"Врач-стажер по специальности «Терапия»\", \"period\": \"Август 2005 - Июль 2006\", \"institution\": \"УЗ «Минская областная клиническая больница»\"}, {\"type\": \"education\", \"title\": \"Переподготовка по специальности «Терапия»\", \"period\": \"Январь 2006 - апрель 2006\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Переподготовка по специальности «Общая врачебная практика»\", \"period\": \"Январь - май 2011\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Профилактика и ранняя диагностика злокачественных новообразований на амбулаторном этапе\", \"period\": \"2011\", \"institution\": \"\"}]','active',0,'2026-04-22 06:33:19','2026-04-22 07:07:31'),(34,10,'Боярчик','Валерий','Петрович','boyarchik-valerij-petrovich','highest',NULL,22,2003,'both','images/doctors/01KPTDADND540431XG0M4BB69F.png','Валерий Петрович Боярчик — врач-хирург по вопросам кардиохирургии, начальник медицинского центра, врач высшей квалификационной категории со стажем 22 года. Имеет профильную подготовку в области хирургии и кардиохирургии, регулярно проходит повышение квалификации по сердечно-сосудистой, рентгенэндоваскулярной и торакальной хирургии.',0.00,'[{\"type\": \"experience\", \"title\": \"Врач-стажер по специальности «Хирургия»\", \"period\": \"2004\", \"institution\": \"УЗ «ГКБ №4» г. Гродно\"}, {\