м, выполнении малоинвазивных вмешательств в амбулаторной хирургии и проктологии, лечении геморроидальной болезни и хронических анальных трещин современными методами.',0.00,'[{\"type\": \"experience\", \"title\": \"Врач-стажер по специальности «Хирургия»\", \"period\": \"2008\", \"institution\": \"Минская ордена Трудового Красного Знамени областная клиническая больница\"}, {\"type\": \"experience\", \"title\": \"Клинический ординатор по специальности «Хирургия»\", \"period\": \"2013\", \"institution\": \"\"}, {\"type\": \"experience\", \"title\": \"Врач-проктолог\", \"period\": \"н.в.\", \"institution\": \"Медицинский центр «Маяк Здоровья»\"}, {\"type\": \"education\", \"title\": \"Высшее медицинское образование\", \"period\": \"2007\", \"institution\": \"Белорусский государственный медицинский университет\"}, {\"type\": \"education\", \"title\": \"Стажировка по специальности «Хирургия»\", \"period\": \"2008\", \"institution\": \"Минская ордена Трудового Красного Знамени областная клиническая больница\"}, {\"type\": \"education\", \"title\": \"Клиническая ординатура по специальности «Хирургия»\", \"period\": \"2013\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Современные технологии в хирургической практике. Инфекции в хирургии\", \"period\": \"2010\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Основы управления здравоохранением в Республике Беларусь\", \"period\": \"2010\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Клиническая фармакология\", \"period\": \"2011\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Медицинская информатика и компьютерные технологии\", \"period\": \"2011\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Лазерная хирургия\", \"period\": \"2014\", \"institution\": \"\"}, {\"type\": \"education\", \"title\": \"Неотложная хирургия органов желудочно-кишечного тракта\", \"period\": \"2016\", \"institution\": \"\"}]','active',0,'2026-04-30 03:46:02','2026