INSERT INTO `equipments` VALUES (1,'Ультразвуковая система «Philips ClearVue 550» (США) высокого класса','philips-clearvue-550','УЗ-диагностика','Медицинское оборудование','Современная экспертная УЗ-система','Позволяет выполнять широкий спектр ультразвуковых исследований: органы брюшной полости, малые и поверхностно расположенные органы, педиатрия, скелетно-мышечная система, урология.','Philips ClearVue 550 — ультразвуковая система высокого класса.\n\nПозволяет выполнять широкий спектр ультразвуковых исследований: органы брюшной полости, малые и поверхностно расположенные органы, педиатрия, скелетно-мышечная система, урология, предстательная железа, акушерство и гинекология, сердце, сосуды и транскраниальная доплерография.\n\nВысокая детализация изображения и точность измерений делают этот аппарат универсальным инструментом для постановки диагноза.','images/medical_equipment/clearvue550_front.png','images/medical_equipment/clearvue550_front.png',10,'active','2026-04-28 12:22:14','2026-04-28 12:22:14'),(2,'Видеокольпоскоп «3MVC LED USB» (Германия) с 3-х ступенчатым увеличением','3mvc-led-usb','Гинекология','Медицинское оборудование','Высокоточный видеокольпоскоп','Позволяет врачу вывести на экран в высоком разрешении имеющиеся патологии у пациента при осмотре.','Видеокольпоскоп 3MVC LED USB — компактный аппарат для современной гинекологии.\n\nПозволяет врачу вывести на экран в высоком разрешении имеющиеся патологии у пациента при осмотре. Три ступени увеличения дают возможность детально изучить состояние тканей.\n\nУдобный USB-интерфейс и LED-подсветка обеспечивают качественное изображение и простоту использования.','images/medical_equipment/videokalposkop-1.png','images/medical_equipment/videokalposkop-1.png',20,'active','2026-04-28 12:22:14','2026-04-28 12:22:14'),(3,'Фракционный лазер «CO2RE» (США) выделяющий волны двойного лазера','co2re-laser','Лазерные технологии','Медицинское оборудование','Единственный CO2 лазер с 7 вариантами лечения','Единственный CO2 лазер, имеющий 7 вариантов лечения, 5 из которых предназначены для обновления кожи.','Фракционный лазер CO2RE — это единственный CO2 лазер, имеющий 7 вариантов лечения, 5 из которых предназначены для обновления кожи.\n\nДвойная лазерная волна обеспечивает одновременную обработку поверхностного и глубокого слоёв кожи, что позволяет добиться выраженного омолаживающего эффекта за минимальное количество процедур.\n\nПрименяется при:\n- возрастных изменениях кожи\n- рубцах постакне\n- пигментации\n- мелких морщинах и потере упругости\n\nПроцедуры проводятся в комфортных условиях с применением современных протоколов обезболивания.','images/medical_equipment/frakczionnyj-lazer-1-1.png','images/medical_equipment/frakczionnyj-lazer-1-1.png',30,'active','2026-04-28 12:22:14','2026-04-28 12:22:14'),(4,'Лазерный аппарат «Mediola Compact» для широкого спектра процедур','mediola-compact','Аппаратные методики','Медицинское оборудование','Универсальный лазерный аппарат','Позволяет проводить хирургические манипуляции в разных направлениях медицинских услуг.','Mediola Compact — компактный универсальный лазерный аппарат.\n\nПозволяет проводить хирургические манипуляции в разных направлениях медицинских услуг: от косметологии до хирургии.\n\nОсобенности аппарата:\n- высокая точность воздействия\n- минимальная травматичность\n- быстрое восстановление\n- широкий выбор насадок и режимов','images/medical_equipment/mediola-compact-4-1.png','images/medical_equipment/mediola-compact-4-1.png',40,'active','2026-04-28 12:22:14','2026-04-28 12:22:14'),(5,'Радиоволновой генератор «Surgitron® Dual EMC™ 90» для хирургических процедур','surgitron-dual-emc-90','Радиоволновая хирургия','Медицинское оборудование','Точные атравматичные разрезы','Генератор позволяет врачу-хирургу виртуозно выполнять точные, атравматичные разрезы кожи и тканей при температуре от 38° до 80° С.','Радиоволновой генератор Surgitron Dual EMC 90 — современный аппарат для хирургических вмешательств.\n\nГенератор позволяет врачу-хирургу виртуозно выполнять точные, атравматичные разрезы кожи и тканей при температуре от 38° до 80° С с абсолютной безопасностью для себя и пациента, обеспечивая великолепный результат.\n\nПреимущества метода:\n- минимальная кровопотеря\n- быстрое заживление\n- отсутствие грубых рубцов\n- безболезненность процедуры','images/medical_equipment/generator-radiovolnovoj-40-mgcz-surgitron™-dual-emc-90-1-1.png','images/medical_equipment/generator-radiovolnovoj-40-mgcz-surgitron™-dual-emc-90-1-1.png',50,'active','2026-04-28 12:22:14','2026-04-28 12:22:14'),(6,'Ультразвуковая система «Philips Affiniti 50» (США) экспертного класса','philips-affiniti-50','Экспертное УЗИ','Медицинское оборудование','Экспертная УЗ-диагностика','Способен выводить на монитор высокодетализированные изображения для эффективной и точной диагностики.','Philips Affiniti 50 — ультразвуковая система экспертного класса.\n\nСпособен выводить на монитор высокодетализированные изображения, с которыми диагностика всегда будет максимально эффективной, точной и достоверной.\n\nИспользуется для исследований сердца, сосудов, органов брюшной полости и малого таза. Обеспечивает максимальную диагностическую точность даже в самых сложных клинических ситуациях.','images/medical_equipment/uzi-affiniti-50-1-1.png','images/medical_equipment/uzi-affiniti-50-1-1.png',60,'active','2026-04-28 12:22:14','2026-04-28 12:22:14'),(7,'Ультразвуковой сканер «VINNO 6» высокого класса','vinno-6','Портативное сканирование','Медицинское оборудование','Портативный УЗ-сканер','Благодаря этому аппарату специалист имеет возможность получить сведения о структуре, размерах и расположении внутренних органов пациента.','VINNO 6 — портативный ультразвуковой сканер высокого класса.\n\nБлагодаря этому аппарату специалист имеет возможность получить сведения о структуре, размерах и расположении внутренних органов пациента.\n\nПодходит для широкого спектра исследований и удобен в применении благодаря компактности и интуитивному интерфейсу.','images/medical_equipment/perenosnoj-skaner-vysokogo-klassa-vinno-6-3-1.png','images/medical_equipment/perenosnoj-skaner-vysokogo-klassa-vinno-6-3-1.png',70,'active','2026-04-28 12:22:14','2026-04-28 12:22:14'),(8,'Центрифуга «Medifuge» (США) для проведения процедур с плазмой крови','medifuge','Плазмотерапия','Медицинское оборудование','Подготовка аутологичной плазмы','За 15 минут подготавливает аутологичную плазму для проведения процедур с её применением.','Medifuge — центрифуга для подготовки аутологичной плазмы крови.\n\nЗа 15 минут подготавливает аутологичную плазму для проведения процедур с её применением.\n\nПлазмолифтинг применяется в:\n- косметологии — омоложение кожи лица и тела\n- ортопедии — лечение суставов\n- гинекологии — восстановительные процедуры\n- трихологии — стимуляция роста волос','images/medical_equipment/czentrifuga-1-1.png','images/medical_equipment/czentrifuga-1-1.png',80,'active','2026-04-28 12:22:14','2026-04-28 12:22:14');
/*!40000 ALTER TABLE `equipments` ENABLE KEYS */;
UNLOCK TABLES;

