INSERT INTO `pages` VALUES (1,'home','Главная','{\"hero\": {\"badge\": \"Более 20 лет опыта\", \"image\": \"images/hero.jpg\", \"title\": \"Маяк Здоровья\", \"subtitle\": \"Многопрофильная клиника в Минске\"}, \"features\": [{\"icon\": \"fa-user-doctor\", \"text\": \"Врачи высшей и первой категории\", \"title\": \"Опытные специалисты\"}, {\"icon\": \"fa-microscope\", \"text\": \"Оборудование экспертного класса\", \"title\": \"Современное оборудование\"}, {\"icon\": \"fa-clock\", \"text\": \"Приём 7 дней в неделю, без очередей\", \"title\": \"Удобная запись\"}, {\"icon\": \"fa-shield-heart\", \"text\": \"Работаем по международным стандартам\", \"title\": \"Гарантия качества\"}]}','2026-04-20 05:55:45','2026-04-20 07:08:49'),(2,'about','О клинике','{\"intro\": \"Клиника «Маяк Здоровья» — многопрофильный медицинский центр в Минске с более чем 20-летним опытом.\", \"stats\": [{\"label\": \"лет опыта\", \"value\": \"20+\"}, {\"label\": \"врачей\", \"value\": \"50+\"}, {\"label\": \"пациентов\", \"value\": \"100 000+\"}, {\"label\": \"направлений\", \"value\": \"15\"}]}','2026-04-20 05:55:45','2026-04-20 07:08:49'),(3,'search','Поиск по сайту','[]','2026-04-20 05:55:45','2026-04-20 05:55:45');
/*!40000 ALTER TABLE `pages` ENABLE KEYS */;
UNLOCK TABLES;

