INSERT INTO `reviews` VALUES (71,16,'Наталья, 70 лет',5,'Была сегодня на УЗИ у врача Алеси Викторовны. Всё быстро, чётко, компетентно. Врач внимательный, опытный и быстро обнаружила полип, который не находили другие врачи. Я очень ей признательна за профессиональную работу и необходимые советы. Спасибо!','approved','2026-03-02 00:00:00','2026-04-20 11:20:32','2026-04-20 11:20:32'),(72,16,'Светлана',5,'Огромная благодарность врачу УЗИ Макеевой Алесе Викторовне за профессиональный подход и чуткость. Исследование провели быстро, качественно и, главное, информативно. Врач сразу указала на проблему и дала ценные рекомендации.','approved','2026-03-02 00:00:00','2026-04-20 11:20:32','2026-04-20 11:20:32'),(73,16,'Иванко Данила',5,'Идеальный врач.','approved','2025-11-24 00:00:00','2026-04-20 11:20:32','2026-04-20 11:20:32'),(126,16,'авфыа',5,'фвыаыва','approved','2026-04-20 17:22:00','2026-04-20 14:22:12','2026-04-20 14:22:41'),(127,16,'аавппв',5,'Была сегодня на УЗИ у врача Алеси Викторовны. Всё быстро, чётко, компетентно. Врач внимательный, опытный и быстро обнаружила полип, который не находили другие врачи. Я очень ей признательна заБыла сегодня на УЗИ у врача Алеси Викторовны. Всё быстро, чётко, компетентно. Врач внимательный, опытный и быстро обнаружила полип, который не находили другие врачи. Я очень ей признательна заБыла сегодня на УЗИ у врача Алеси Викторовны. Всё быстро, чётко, компетентно. Врач внимательный, опытный и быстро обнаружила полип, который не находили другие врачи. Я очень ей признательна заБыла сегодня на УЗИ у врача Алеси Викторовны. Всё быстро, чётко, компетентно. Врач внимательный, опытный и быстро обнаружила полип, который не находили другие врачи. Я очень ей признательна заБыла сегодня на УЗИ у врача Алеси Викторовны. Всё быстро, чётко, компетентно. Врач внимательный, опытный и быстро обнаружила полип, который не находили другие врачи. Я очень ей признательна заБыла сегодня на УЗИ у врача Алеси Викторовны. Всё быстро, чётко, компетентно. Врач вн