INSERT INTO `services` VALUES (181,11,'Консультация врача-эндокринолога','konsultaciya-vracha-endokrinologa',44.66,30,'Профессиональная консультация для диагностики и лечения патологий эндокринной системы, анализа гормонального фона и назначения индивидуальной схемы терапии.\n\nЧто включает консультация:\n• Сбор жалоб с их детализацией;\n• Сбор анамнестических данных заболевания;\n• Выявление факторов риска заболеваний;\n• Интерпретация результатов клинико-лабораторных и инструментальных исследований;\n• Проведение общего осмотра (оценка сознания, телосложения, осмотр кожных покровов и видимых слизистых оболочек, типологическая оценка нервной деятельности, выполнение антропометрических измерений, измерение температуры тела, артериального давления, частоты пульса, частоты дыхания и другое);\n• Проведение пальпации, перкуссии, аускультации;\n• Установление клинико-функционального диагноза;\n• Определение тактики лечения и индивидуальных рекомендаций по медицинскому наблюдению;\n• Назначение медикаментозного и немедикаментозного лечения;\n• Оформление медицинской документации и консультативного заключения.','Слабость, утомляемость, сонливость; подавленное настроение, раздражительность; учащенное сердцебиение, повышенное потоотделение, дрожание рук или ног; резкое похудение или стремительный набор веса; сухость кожи, выпадение волос; плохая переносимость тепла или холода; жажда, сухость во рту, частое мочеиспускание; зуд кожи, генитальный зуд; повышение артериального давления, которое не поддаётся снижению препаратами; нарушение менструального цикла у женщин; бесплодие у мужчин и женщин; невынашивание беременности; выделения из молочных желез у женщин вне беременности и лактации; увеличение грудных желез у мужчин; избыточный рост волос у женщин; яркие широкие растяжки на коже; переломы костей при незначительных травмах; снижение либидо и другие половые нарушения.','Специальной подготовки не требуется. Рекомендуется взять с собой результаты предыдущих анализов и обследований (при наличии)','active',0,'2026-04-21 10:53:42','2026-04-21 10:53:42'),(182,11,'Консультация детского врача-эндокринолога','konsultaciya-detskogo-vracha-endokrinologa',44.66,30,'Консультация детского эндокринолога проводится по предварительной записи. Специалист занимается диагностикой и лечением заболеваний желез внутренней секреции у детей и подростков, а также оценкой физического и полового развития ребенка.','Слабость, утомляемость, сонливость; подавленное настроение, раздражительность; учащенное сердцебиение, повышенное потоотделение, дрожание рук или ног; резкое похудение или стремительный набор веса; сухость кожи, выпадение волос; плохая переносимость тепла или холода; жажда, сухость во рту, частое мочеиспускание; зуд кожи; повышение артериального давления, которое не поддаётся снижению препаратами; увеличение грудных желез у мальчиков; избыточный рост волос у девочек; переломы костей при незначительных травмах.','Специальной подготовки не требуется. Рекомендуется взять с собой амбулаторную карту ребенка, результаты предыдущих анализов крови (гормоны, сахар), УЗИ щитовидной железы (при наличии).','active',0,'2026-04-21 10:56:16','2026-04-21 10:56:16'),(183,11,'Установка врачом-эндокринологом инсулиновой помпы пациенту с сахарным диабетом','ustanovka-vrachom-endokrinologom-insulinovoy-pompy-pacientu-s-saharnym-diabetom',55.35,30,'Инсулиновая помпа повышает качество жизни пациентов с сахарным диабетом: компактное устройство заменяет ежедневные инъекции инсулина.\n\nКому подойдёт этот способ введения инсулина?\n\n- Детям любого возраста, которые страдают сахарным диабетом (СД).\n- Женщинам, которые планируют беременность на фоне сахарного диабета.\n- Пациентам с СД, которые измеряют уровень глюкозы в крови не меньше 4 раз и считают хлебные единицы.\n- Пациентам с СД, у которых не всегда есть возможность вовремя сделать укол.\n- Пациентам с СД, у которых в течение суток отмечается нестабильный уровень глюкозы в крови.\n- Пациентам с тяжелым течением СД или при невозможности добиться стабильного уровня глюкозы другими методами.\n\nКак работает помпа?\nВ инсулиновой помпе используется инсулин короткого или ультракороткого действия. Различают два вида подачи:\n\nБазальный: инсулин вводится в нужной дозе на протяжении суток с заданным интервалом.\n\nБолюсный: вводится перед едой или сразу после.\n\nВажные условия использования:\nПеред принятием душа/ванны, походом в бассейн или на время занятий спортом помпу необходимо снимать','Детям любого возраста, которые страдают сахарным диабетом (СД). Женщинам, которые планируют беременность на фоне сахарного диабета. Пациентам с СД, которые измеряют уровень глюкозы в крови не меньше 4 раз и считают хлебные единицы. Пациентам с СД, у которых не всегда есть возможность вовремя сделать укол (например, на работе). Пациентам с СД, у которых в течение суток отмечается нестабильный уровень глюкозы в крови: с эпизодами гипергликемии и гипогликемии. Пациентам, у которых тяжело протекает СД. Пациентам с СД, у которых не удаётся добиться стабильного уровня глюкозы в крови другими методами.','Перед установкой инсулиновой помпы необходимо пройти консультацию эндокринолога для исключения противопоказаний. Рекомендуется иметь при себе дневник самоконтроля уровня глюкозы за последние 1-2 недели.','active',0,'2026-04-21 10:57:38','2026-04-21 10:59:33'),(184,11,'Пункционная биопсия щитовидной железы','punkcionnaya-biopsiya-schitovidnoy-zhelezy',67.42,30,'Для изучения состояния щитовидной железы используют разные методы, но только биопсия поможет отличить злокачественное новообразование от доброкачественного.\n\nПроцедура выполняется под контролем УЗИ. Занимает она от 10 до 25 минут. Пациент лежит на спине. Кожу шеи обрабатывают антисептиком. Тонкой иглой пунктируют узел. Полученный материал отправляют на цитологию, чтобы определить характер клеток. При необходимости забор клеток может осуществляться из разных мест одного узла или из разных узлов.\n\nРезультат биопсии помогает определиться с дальнейшей тактикой ведения пациента. Эта процедура практически безболезненная. Пациент испытывает лишь незначительный дискомфорт.','Размер узла 1 см и более. Размер узла меньше 1 см, но есть сомнения в том, что он доброкачественный. Наследственная предрасположенность к раку щитовидной железы.','Специальной подготовки не требуется. Рекомендуется иметь при себе результаты предыдущих УЗИ щитовидной железы и заключение эндокринолога о направлении на биопсию.','active',0,'2026-04-21 11:01:27','2026-04-21 11:01:27'),(185,11,'Онлайн консультация врача-детского эндокринолога первой категории','onlayn-konsultaciya-vracha-detskogo-endokrinologa-pervoy-kategorii',44.00,30,'Онлайн консультация врача-детского эндокринолога первой категории — это удобный способ получить квалифицированную медицинскую помощь, не выходя из дома. Формат онлайн-приема позволяет обсудить результаты анализов, скорректировать лечение или получить первичные рекомендации по поводу роста, развития и гормонального фона ребенка.\n\nВ рамках онлайн консультации врач выполняет:\n• Сбор жалоб с их детализацией;\n• Сбор анамнестических данных заболевания;\n• Выявление факторов риска заболеваний;\n• Интерпретацию результатов клинико-лабораторных и инструментальных исследований;\n• Установление клинико-функционального диагноза;\n• Определение тактики лечения и индивидуальных рекомендаций по медицинскому наблюдению;\n• Назначение медикаментозного и немедикаментозного лечения;\n• Оформление медицинской документации;\n• Оформление консультативного заключения.\n\nОбратите внимание: онлайн формат имеет ограничения. Врач не может провести физикальный осмотр, пальпацию, аускультацию и измерение антропометрических данных. При необходимости очного визита специалист сообщит об этом во время консультации.','Необходимость повторного приема для оценки динамики лечения. Расшифровка и интерпретация уже готовых результатов анализов крови (гормоны, глюкоза), УЗИ щитовидной железы, рентгенографии кистей рук. Коррекция дозировок ранее назначенных препаратов (инсулин, гормональная терапия). Консультация по вопросам питания, режима дня и физической активности ребенка. Жалобы на слабость, утомляемость, изменения веса, которые не требуют экстренного очного вмешательства. Невозможность посетить клинику лично (проживание в другом городе, карантин).','Для качественной консультации необходимо заранее подготовить и отправить врачу (или иметь перед глазами во время видеозвонка) следующую информацию:\n• Актуальные результаты лабораторных исследований (гормоны ТТГ, Т4 свободный, глюкоза, инсулин и др.).\n• Результаты инструментальных исследований (УЗИ щитовидной железы, органов малого таза и др.).\n• Дневник самоконтроля уровня сахара крови (для пациентов с сахарным диабетом).\n• Данные о росте и весе ребенка за последние полгода-год.\n• Список принимаемых в настоящее время лекарственных препаратов с указанием дозировок.\n• Четкий перечень жалоб и вопросов к врачу.','active',0,'2026-04-21 11:02:40','2026-04-21 11:02:40'),(186,5,'Консультация врача-акушера-гинеколога','konsultaciya-vracha-akushera-ginekologa',44.15,30,'Консультация гинеколога — это прием специалиста, направленный на диагностику, лечение и профилактику заболеваний женской репродуктивной системы. Посещение врача рекомендовано с профилактической целью ежегодно, даже при отсутствии жалоб.\n\nКак проходит консультация:\n• Сбор жалоб с их детализацией;\n• Сбор анамнестических данных заболевания;\n• Выявление факторов риска заболеваний;\n• Интерпретация результатов клинико-лабораторных и инструментальных исследований;\n• Проведение общего осмотра (оценка сознания, телосложения, осмотр кожных покровов и видимых слизистых оболочек, типологическая оценка нервной деятельности, выполнение антропометрических измерений, измерение температуры тела, артериального давления, частоты пульса, частоты дыхания и другое);\n• Проведение пальпации, перкуссии, аускультации;\n• Установление клинико-функционального диагноза;\n• Определение тактики лечения и индивидуальных рекомендаций по медицинскому наблюдению;\n• Назначение медикаментозного и немедикаментозного лечения;\n• Оформление медицинской документации;\n• Оформление консультативного заключения.\n\nКроме диагностики и лечения, к гинекологу можно обратиться для обсуждения вопросов контрацепции и планирования беременности.','С профилактической целью — ежегодно. При появлении следующих жалоб:\n• Сыпь и покраснение слизистой наружных половых органов;\n• Зуд и жжение;\n• Боли внизу живота;\n• Необычные выделения и/или неприятный запах из половых путей;\n• Нарушение менструального цикла;\n• Кровянистые выделения в период между менструациями;\n• Болезненный половой акт;\n• Бесплодие;\n• Планирование беременности;\n• Подбор контрацепции.','• Надеть чистое бельё;\n• Накануне вечером принять душ;\n• В течение 2-3 дней перед консультацией отказаться от половых контактов;\n• Перед тем, как зайти в кабинет гинеколога, посетить туалет и опорожнить мочевой пузырь;\n• Подобрать удобную одежду, которую легко снимать и надевать.','active',0,'2026-04-21 11:04:36','2026-04-21 11:04:36'),(187,5,'Общий мазок на флору','obschiy-mazok-na-floru',15.00,30,'Общий мазок на флору — это лабораторное исследование, которое используют для первичной диагностики гинекологической патологии. Анализ позволяет оценить состояние микрофлоры влагалища, выявить наличие воспалительного процесса, грибковой или бактериальной инфекции. Специалисты рекомендуют проходить данное исследование не реже одного раза в год.\n\nПроцедура забора материала занимает несколько минут и выполняется во время гинекологического осмотра. Полученный биоматериал направляется в лабораторию для микроскопического исследования. Результаты анализа помогают врачу поставить точный диагноз и назначить эффективное лечение.\n\nЗаписаться на мазок на флору рекомендуется также в следующих ситуациях:\n• Перед операцией на органах малого таза;\n• Перед проведением инвазивных диагностических процедур;\n• При планировании беременности;\n• После прохождения курса антибиотиков;\n• При смене полового партнёра;\n• Для оценки результатов проведенного лечения.','• Жжение, зуд, сухость во влагалище;\n• Боли внизу живота и/или поясничной области;\n• Болезненный половой акт;\n• Изменение характера выделений;\n• Кровомазание в период между менструациями;\n• Частые позывы и боль при мочеиспускании;\n• Плохой анализ мочи;\n• Планирование беременности;\n• Подготовка к операциям на органах малого таза;\n• Смена полового партнёра;\n• Контроль эффективности лечения;\n• Профилактическое обследование (1 раз в год).','• В течение 2-3 дней перед исследованием не заниматься сексом;\n• В течение 2-3 дней перед исследованием не спринцеваться;\n• Не использовать лекарственные средства, которые вводятся во влагалище (свечи, кремы, таблетки);\n• За сутки до анализа не принимать ванну (можно принять душ);\n• В день приёма выполнить туалет наружных половых органов водой без использования мыла и гелей для интимной гигиены;\n• За 2-3 часа до взятия мазка воздержаться от мочеиспускания.','active',0,'2026-04-21 11:06:02','2026-04-21 11:06:02'),(188,5,'Цитология','citologiya',23.00,30,'Мазок на цитологию (онкоцитологию) — это современный и высокоточный метод лабораторной диагностики, направленный на выявление новообразований, предраковых состояний и воспалительных заболеваний шейки матки. Исследование позволяет оценить структуру клеток, их размер, форму и степень зрелости, что дает возможность обнаружить патологические изменения на самых ранних стадиях.\n\nРак шейки матки часто протекает бессимптомно на начальных этапах, поэтому регулярное обследование у гинеколога является жизненно важным. Специалисты рекомендуют проходить цитологическое исследование ежегодно.\n\nМазок на цитологию используют для:\n• Выявления воспалительных, инфекционных и онкологических заболеваний;\n• Оценки результатов проведенного лечения;\n• Скринингового обследования здоровых женщин;\n• Своевременного выявления возможных рецидивов онкозаболеваний.\n\nПроцедура забора материала проводится во время гинекологического осмотра, занимает несколько минут и не вызывает выраженных болевых ощущений. Полученный биоматериал направляется в лабораторию для микроскопического исследования.','• Инфекции, которые передаются половым путём;\n• Герпес на гениталиях;\n• Необычные выделения из половых путей;\n• Осложнённые роды, аборты, операции в анамнезе;\n• Эрозия шейки матки;\n• Ремиссия онкологических заболеваний (контроль);\n• Планирование беременности;\n• Патология тканей, обнаруженная гинекологом при осмотре или на кольпоскопии;\n• Ежегодное профилактическое обследование;\n• Нарушения менструального цикла неясной этиологии;\n• Длительный приём гормональных контрацептивов.','• За 2-3 дня до исследования исключить половые контакты;\n• За 2-3 дня до исследования не проводить спринцевания;\n• За 2-3 дня до исследования не использовать вагинальные лекарственные средства (свечи, кремы, таблетки);\n• За сутки до анализа не принимать ванну (можно принять душ);\n• В день процедуры выполнить туалет наружных половых органов водой без использования мыла и гелей для интимной гигиены;\n• Исследование не проводится во время менструации (оптимальный срок — через 2-3 дня после её окончания);\n• За 2 часа до взятия мазка воздержаться от мочеиспускания.','active',0,'2026-04-21 11:06:52','2026-04-21 11:06:52'),(189,21,'Лазерное удаление кондилом и других доброкачественных новообразований гениталий, лазер Mediola','lazernoe-udalenie-kondilom-i-drugih-dobrokachestvennyh-novoobrazovaniy-genitaliy-lazer-mediola',68.90,30,'Лазерное удаление кондилом и других доброкачественных новообразований гениталий с использованием аппарата Mediola — это современный, высокоэффективный и безопасный метод лечения. Кондилома представляет собой разрастание на коже или слизистой оболочке, по внешнему виду напоминающее цветную капусту. Причиной её образования является вирус папилломы человека (ВПЧ).\n\nКондиломы и другие доброкачественные образования не только являются косметическим дефектом, но и причиняют психологический дискомфорт, мешают полноценной интимной жизни. Новообразования легко травмируются при ношении белья, гигиенических процедурах или половом контакте, что может приводить к кровоточивости, воспалению, присоединению вторичной инфекции. Кроме того, некоторые типы ВПЧ обладают онкогенным потенциалом и могут способствовать развитию злокачественных процессов.\n\nЛазер Mediola обеспечивает удаление новообразований методом вапоризации (послойного выпаривания тканей). Процедура проходит под местной анестезией и занимает от 15 до 40 минут в зависимости от количества и размера элементов.\n\nПреимущества лазерного удаления аппаратом Mediola:\n• Бескровность — лазерный луч моментально запаивает сосуды;\n• Безболезненность — процедура проводится под местным обезболиванием;\n• Безопасность — воздействие происходит строго на патологическую ткань, здоровые участки не повреждаются;\n• Стерильность — высокая температура луча исключает риск инфицирования раны;\n• Отсутствие рубцов и ожогов — заживление происходит быстро, без формирования грубой рубцовой ткани;\n• Короткий период восстановления.\n\nУдаление выполняется в трех вариантах объема в зависимости от количества новообразований:\n• до 5 штук;\n• от 5 до 20 штук;\n• более 20 штук (множественные).','• Наличие остроконечных кондилом на коже и слизистых оболочках гениталий;\n• Наличие папиллом, кератом, невусов (родинок) в интимной зоне;\n• Дискомфорт, зуд, жжение в области новообразований;\n• Кровоточивость или воспаление кондилом при травматизации;\n• Психологический дискомфорт, связанный с наличием косметического дефекта;\n• Планирование беременности при наличии ВПЧ и кондилом;\n• Риск малигнизации (озлокачествления) новообразований;\n• Желание пациента удалить доброкачественные образования с эстетической целью.','• Обязательная предварительная консультация гинеколога (для женщин) или уролога (для мужчин) для определения объема вмешательства и исключения противопоказаний;\n• За 2 недели до процедуры исключить пребывание на активном солнце, отказ от солярия;\n• За 7 дней до удаления исключить использование агрессивных косметических средств в зоне воздействия;\n• За 2-3 дня до процедуры исключить половые контакты;\n• В день процедуры выполнить гигиенический туалет наружных половых органов без использования мыла и гелей;\n• На процедуру надеть чистое, удобное бельё из натуральных тканей;\n• При наличии обильного волосяного покрова в зоне воздействия рекомендуется провести деликатную депиляцию за 2-3 дня до процедуры (бритьё в день процедуры не допускается);\n• Сообщить врачу о принимаемых лекарственных препаратах, особенно о средствах, влияющих на свертываемость крови (антикоагулянты, аспирин).','active',0,'2026-04-21 11:09:01','2026-04-21 11:09:01'),(190,21,'Лазерное удаление (вапоризация) кондилом и других доброкачественных новообразований гениталий, СО2-лазер','lazernoe-udalenie-vaporizaciya-kondilom-i-drugih-dobrokachestvennyh-novoobrazovaniy-genitaliy-so2-lazer',131.79,30,'Лазерное удаление (вапоризация) кондилом и других доброкачественных новообразований гениталий с использованием СО2-лазера — это высокоточный и эффективный метод избавления от нежелательных образований на коже и слизистых оболочках интимной зоны. Кондиломы и папилломы представляют собой доброкачественные разрастания, вызванные вирусом папилломы человека (ВПЧ), и часто локализуются на половых губах, во влагалище, на шейке матки, в перианальной области.\n\nВ клинике применяются две современные лазерные системы: СО2-лазер и Mediola. Выбор конкретного вида аппарата осуществляет лечащий врач индивидуально, исходя из типа кожи пациентки, локализации, размера и количества новообразований. Обе системы обеспечивают высочайшую точность и безопасность вмешательства.\n\nПринцип действия СО2-лазера основан на послойном выпаривании (вапоризации) патологических тканей под воздействием высокоэнергетического лазерного луча. Ключевым преимуществом метода является избирательность воздействия: удаляется только само новообразование, здоровые окружающие ткани не затрагиваются и не повреждаются. Это выгодно отличает лазерную вапоризацию от хирургического иссечения скальпелем, электрокоагуляции или криодеструкции, при которых травматизация здоровых участков неизбежна.\n\nПроцедура проводится под местной анестезией и занимает от 15 до 40 минут в зависимости от площади обработки. После удаления на месте воздействия формируется тонкая корочка, которая самостоятельно отпадает через 7-10 дней. Заживление происходит быстро, без формирования грубых рубцов и с минимальным дискомфортом для пациентки.\n\nУдаление СО2-лазером выполняется в трех вариантах в зависимости от площади обрабатываемой поверхности:\n• Область обработки до 1 см²;\n• Область обработки от 1 до 2 см²;\n• Область обработки более 2 см².','• Наличие папиллом на коже и слизистых оболочках гениталий;\n• Наличие остроконечных кондилом (единичных или множественных);\n• Наличие других доброкачественных новообразований в интимной зоне (кератомы, невусы);\n• Дискомфорт, зуд, жжение в области расположения новообразований;\n• Кровоточивость или воспаление при травматизации кондилом;\n• Психологический дискомфорт, эстетические жалобы;\n• Планирование беременности при наличии ВПЧ-инфекции с клиническими проявлениями;\n• Риск малигнизации (озлокачествления) новообразований;\n• Желание пациентки удалить образования с косметической целью.','• Обязательная предварительная консультация гинеколога для определения объема вмешательства, выбора типа лазера и исключения противопоказаний;\n• Проведение кольпоскопии и цитологического исследования (по назначению врача);\n• За 2 недели до процедуры исключить пребывание на активном солнце и посещение солярия;\n• За 7 дней до удаления исключить использование агрессивных косметических средств в зоне воздействия;\n• За 2-3 дня до процедуры исключить половые контакты;\n• В день процедуры выполнить гигиенический туалет наружных половых органов водой без использования мыла и гелей;\n• На процедуру надеть чистое, удобное бельё из натуральных тканей;\n• При наличии обильного волосяного покрова в зоне воздействия рекомендуется провести деликатную депиляцию за 2-3 дня до процедуры (бритьё в день процедуры не допускается);\n• Сообщить врачу о принимаемых лекарственных препаратах, особенно о средствах, влияющих на свертываемость крови (антикоагулянты, аспирин);\n• Процедура не проводится во время менструации (оптимальный срок — через 3-5 дней после её окончания).','active',0,'2026-04-21 11:10:17','2026-04-21 11:10:17'),(191,21,'Интимное лазерное омоложение','intimnoe-lazernoe-omolozhenie',278.09,30,'Интимное лазерное омоложение — это современная аппаратная процедура, направленная на восстановление эстетики и нормализацию функции интимной зоны с использованием лазера Candela CO2RE Intima. Красота, здоровье и молодость интимной зоны напрямую влияют на чувство собственного достоинства, уверенность в себе, любовь и уважение к собственному телу.\n\nСпециалисты медицинского центра «Маяк Здоровья» проводят процедуру на инновационном лазерном аппарате Candela CO2RE Intima, который обеспечивает фракционное воздействие на слизистую оболочку и кожу интимной зоны. Лазерный луч создает микроскопические зоны термического воздействия, запуская естественные процессы регенерации и обновления тканей. В результате активизируется выработка собственного коллагена, эластина и гиалуроновой кислоты.\n\nЧто даёт эта процедура:\n• Восстановление тонуса и упругости тканей влагалища и вульвы;\n• Уменьшение или полное исчезновение сухости слизистых оболочек;\n• Улучшение местного кровообращения и обменных процессов;\n• Усиление или возвращение сексуальной чувствительности;\n• Осветление участков гиперпигментации в интимной зоне;\n• Уменьшение проявлений недержания мочи при кашле, чихании, физической нагрузке;\n• Устранение дискомфорта и болезненности при половом акте.\n\nПроцедура проходит быстро, безопасно и безболезненно. Положительные изменения ощущаются уже после первого сеанса. Для достижения стойкого и выраженного результата рекомендуется курс из 3 процедур с интервалом 45-60 дней между сеансами.','• Снижение тонуса мышц половых органов после естественных родов;\n• Опущение влагалища первой или второй степени;\n• Снижение сексуальной чувствительности;\n• Воспалительные заболевания, сопровождающиеся зудом, жжением, сухостью и раздражением;\n• Возрастные изменения: дряблость и атрофия тканей, гиперпигментация вульвы и перианальной области;\n• Недержание мочи (особенно стрессовое — при кашле, чихании, прыжках, физической нагрузке);\n• Болезненность при половом акте (диспареуния);\n• Желание улучшить эстетический вид интимной зоны;\n• Подготовка к пластическим операциям в интимной зоне и реабилитация после них.','• Обязательная предварительная консультация гинеколога для оценки состояния тканей, определения показаний и исключения противопоказаний;\n• Проведение кольпоскопии и цитологического исследования (ПАП-тест) не позднее чем за 6 месяцев до процедуры;\n• За 2 недели до процедуры исключить пребывание на активном солнце и посещение солярия;\n• За 7 дней до процедуры исключить использование агрессивных косметических средств в зоне воздействия;\n• За 2-3 дня до процедуры исключить половые контакты;\n• В день процедуры выполнить гигиенический туалет наружных половых органов водой без использования мыла и гелей;\n• На процедуру надеть чистое, удобное бельё из натуральных тканей;\n• Процедура не проводится во время менструации (оптимальный срок — через 3-5 дней после её окончания);\n• Сообщить врачу о наличии герпетической инфекции в анамнезе (может потребоваться профилактический приём противовирусных препаратов).','active',0,'2026-04-21 11:11:25','2026-04-21 11:11:25'),(192,9,'Полный проктологический осмотр','polnyy-proktologicheskiy-osmotr',91.67,30,'Консультация проктолога с полным обследованием в клинике экспертной медицины «Маяк Здоровья» в Минске проводится по предварительной записи. Чтобы преодолеть стеснение перед приёмом, пациент может выбрать врача-проктолога своего пола — женщину или мужчину. Специалисты клиники консультируют беременных женщин, женщин после родов, мужчин и женщин всех возрастов, подбирая лечение, которое эффективно решает проблемы пациентов.\n\nСимптомы, характерные для проктологических заболеваний, во многом схожи с проявлениями злокачественных новообразований прямой и толстой кишки. Поэтому своевременный визит к проктологу помогает обнаружить заболевание на ранней стадии и своевременно направить пациента в специализированное учреждение.\n\nКак проводится консультация проктолога:\n\n1. Беседа с пациентом. Врач уточняет жалобы с помощью специальных вопросов, собирает историю заболевания, выясняет наличие сопутствующей патологии.\n\n2. Проктологический осмотр. Это обязательный этап консультации, который включает в себя осмотр перианальной области, анального канала и прямой кишки. Данное исследование позволяет установить или предположить наличие более 80% возможных проктологических заболеваний. Проводить проктологический осмотр может только врач-проктолог.\n\nОсмотр проводится на высокой кушетке в положении пациента лёжа на боку или в коленно-локтевой позе. Врач выполняет все манипуляции аккуратно и малотравматично.\n\nВ ходе проктологического осмотра проктолог выполняет:\n• Пальцевое исследование анального канала и нижних отделов прямой кишки;\n• Аноскопию;\n• Ректороманоскопию.\n\nЭти исследования позволяют оценить состояние анального канала, мышц тазового дна, прямой кишки и её слизистой оболочки, выявить наличие воспалительных изменений, повреждений целостности кожи и слизистой, патологических образований, изменений вен геморроидальных сплетений.\n\nПроктологический осмотр может доставлять пациенту небольшой дискомфорт, болевые ощущения возникают редко (при наличии трещины или острого воспалительного процесса). При необходимости врач использует специальные мази с анестетиком. Важно понимать, что одной беседы без осмотра недостаточно для постановки точного диагноза, но этот этап визита к проктологу не так страшен, как его часто представляют.\n\n3. Заключение. После осмотра врач формулирует диагноз, объясняет пациенту возможные причины заболевания, обсуждает варианты лечения, а также меры профилактики обострений.','• Боль, зуд, жжение и дискомфорт во время или после дефекации;\n• Кровь или слизистые выделения в стуле, на туалетной бумаге или на белье;\n• Боли в прямой кишке или чувство инородного тела в области ануса во время сидения, стояния, ходьбы;\n• Краснота, припухлость, зуд в области заднего прохода;\n• Непонятные образования в анальной области;\n• Хронические запоры или диарея;\n• Ощущение неполного опорожнения кишечника;\n• Профилактический осмотр (особенно при отягощенном семейном анамнезе по раку толстой кишки);\n• Беременность и послеродовой период (при наличии жалоб);\n• Контроль эффективности ранее назначенного лечения.','Для качественного проведения проктологического осмотра необходима предварительная подготовка кишечника:\n\n• За 2-3 дня до консультации исключить из рациона продукты, вызывающие повышенное газообразование (бобовые, капуста, чёрный хлеб, газированные напитки, свежие овощи и фрукты, молоко);\n• Накануне приёма — лёгкий ужин не позднее 19:00;\n• Утром в день приёма — лёгкий завтрак (чай, каша на воде) не позднее чем за 2-3 часа до визита;\n• За 1-2 часа до приёма опорожнить кишечник естественным путём;\n• При необходимости (при склонности к запорам) можно использовать очистительную микроклизму (Микролакс) утром в день приёма;\n• Выполнить гигиенический туалет перианальной области;\n• Взять с собой на приём имеющиеся результаты предыдущих обследований (колоноскопия, ирригоскопия, УЗИ, анализы).','active',0,'2026-04-21 11:13:51','2026-04-21 11:13:51'),(193,9,'Лазерное лечение хронической анальной трещины','lazernoe-lechenie-hronicheskoy-analnoy-treschiny',806.95,30,'Лазерное лечение хронической анальной трещины — это современный малоинвазивный метод, который давно зарекомендовал себя как эффективный и щадящий способ избавления от данной патологии. Процедура выполняется с минимальным вмешательством и коротким периодом восстановления.\n\nСуть процедуры:\nПод местной анестезией лазерный луч воздействует на поверхность анальной трещины. При этом затрагиваются исключительно патологически измененные ткани, воздействие на здоровую слизистую оболочку полностью исключено. Лазерная энергия способствует коагуляции (запаиванию) нервных окончаний и сосудов в области трещины, что устраняет болевой синдром, снимает спазм сфинктера и создает оптимальные условия для быстрого заживления. Продолжительность процедуры составляет около 20 минут, что позволяет провести её в амбулаторных условиях с краткосрочным пребыванием в медицинском центре.\n\nПреимущества лазерного лечения:\n• Минимальное воздействие на ткани, что обеспечивает быстрое заживление;\n• Возможность проведения процедуры в амбулаторном режиме (продолжительность около 20 минут);\n• Минимальный риск послеоперационных осложнений;\n• Полное отсутствие контакта инструмента с телом пациента, что исключает риск занесения инфекции;\n• Процедура выполняется без наложения швов, что избавляет от необходимости в последующих перевязках;\n• Отсутствие выраженного болевого синдрома в послеоперационном периоде;\n• Сохранение нормальной функции анального сфинктера;\n• Быстрое возвращение к привычному образу жизни.\n\nРекомендации после проведённой процедуры:\nОсобых строгих ограничений нет. В первые дни после процедуры рекомендуется:\n• Воздержаться от тяжелых физических нагрузок;\n• Воздержаться от половых контактов (срок уточнит лечащий врач);\n• Соблюдать тщательную гигиену перианальной области;\n• Исключить употребление острой, пряной пищи и алкоголя;\n• Соблюдать диету, направленную на профилактику запоров (употребление достаточного количества клетчатки и жидкости);\n• Использовать назначенные врачом местные средства (мази, кремы) для ускорения заживления.','• Хроническая анальная трещина, не поддающаяся консервативному лечению (длительность заболевания более 1-2 месяцев);\n• Острая анальная трещина при неэффективности медикаментозной терапии;\n• Рецидивирующая анальная трещина;\n• Анальная трещина, сопровождающаяся выраженным болевым синдромом и спазмом сфинктера;\n• Анальная трещина, осложненная кровотечением;\n• Наличие противопоказаний к традиционному хирургическому иссечению трещины;\n• Желание пациента провести малоинвазивное лечение с коротким периодом реабилитации.','• Обязательная предварительная консультация проктолога для подтверждения диагноза, определения показаний и исключения противопоказаний;\n• За 2-3 дня до процедуры исключить из рациона продукты, вызывающие повышенное газообразование и запоры (бобовые, капуста, чёрный хлеб, острая и жирная пища, алкоголь);\n• Накануне процедуры — лёгкий ужин не позднее 19:00;\n• Утром в день процедуры — лёгкий завтрак не позднее чем за 2-3 часа до вмешательства;\n• За 1-2 часа до процедуры опорожнить кишечник естественным путём или с помощью очистительной микроклизмы (Микролакс);\n• Выполнить гигиенический туалет перианальной области;\n• На процедуру надеть чистое, удобное бельё из натуральных тканей;\n• Сообщить врачу о принимаемых лекарственных препаратах, особенно о средствах, влияющих на свертываемость крови (антикоагулянты, аспирин).','active',0,'2026-04-21 11:14:53','2026-04-21 11:14:53'),(194,10,'Консультация врача-хирурга','konsultaciya-vracha-hirurga',42.66,30,'Хирурги медицинского центра «Маяк Здоровья» осуществляют консультативную помощь и проводят оперативное лечение широкого спектра заболеваний. Прием ведут опытные специалисты, которые простыми и доступными словами расскажут о любой хирургической патологии, тщательно соберут анамнез, бережно проведут осмотр и назначат необходимые обследования. На основании полученных данных врач поставит верный диагноз и составит индивидуальный план лечения. При наличии показаний хирурги центра выполнят оперативное вмешательство в условиях современной операционной с использованием малоинвазивных и органосохраняющих технологий.\n\nПациенты обращаются за помощью к хирургам по различным вопросам:\n• Боли в животе различного характера;\n• Боли в суставах;\n• Грыжи: паховые, пупочные, бедренные, белой линии живота, послеоперационные и другие;\n• Вросший ноготь;\n• Воспаление лимфоузлов;\n• Геморрой, анальная трещина;\n• Гангрена;\n• Гнойные заболевания кожи: панариций, абсцесс, флегмона, фурункул, карбункул, гидраденит;\n• Кожные и подкожные образования: кератомы, липомы, атеромы, папилломы, фибромы, невусы (родинки), бородавки, гигромы;\n• Перевязка и снятие швов после операций;\n• Трофические язвы;\n• Диабетическая стопа;\n• Варикозное расширение вен нижних конечностей;\n• Желчнокаменная болезнь и её осложнения;\n• И многие другие хирургические проблемы.\n\nСпециалисты центра применяют комплексный подход к лечению, уделяя внимание не только устранению самой патологии, но и профилактике рецидивов, а также скорейшей реабилитации пациента.','Консультация хирурга показана при наличии следующих жалоб и состояний:\n• Боли в животе любого характера (острые, ноющие, схваткообразные);\n• Боли в суставах, ограничение подвижности, отек и покраснение в области сустава;\n• Наличие грыжевого выпячивания в паховой, пупочной, бедренной области или по белой линии живота;\n• Вросший ноготь, сопровождающийся болью, покраснением, отеком, гнойным отделяемым;\n• Увеличение, болезненность, покраснение лимфатических узлов;\n• Симптомы геморроя: боль, зуд, жжение, кровотечение, выпадение узлов;\n• Анальная трещина: боль и кровотечение при дефекации;\n• Гнойные заболевания кожи и подкожной клетчатки: панариций, абсцесс, флегмона, фурункул, карбункул, гидраденит;\n• Наличие любых кожных или подкожных образований: родинки, папилломы, бородавки, липомы, атеромы, фибромы, гигромы, кератомы;\n• Необходимость перевязки или снятия швов после хирургических вмешательств;\n• Трофические язвы, длительно незаживающие раны;\n• Признаки гангрены: потемнение кожи, потеря чувствительности, неприятный запах;\n• Травмы: ушибы, растяжения, раны, ожоги, отморожения.','Специальной подготовки для первичной консультации хирурга не требуется. Рекомендуется:\n• Принять душ, надеть чистое бельё и удобную одежду, обеспечивающую легкий доступ к зоне осмотра;\n• Взять с собой имеющиеся результаты предыдущих обследований, относящихся к проблеме (УЗИ, рентген, МРТ, КТ, анализы крови, выписки из стационаров);\n• Составить список принимаемых лекарственных препаратов с указанием дозировок;\n• Сформулировать четкий перечень жалоб и вопросов к врачу;\n• Если планируется осмотр брюшной полости или паховой области — желательно опорожнить кишечник и мочевой пузырь перед приёмом.','active',0,'2026-04-21 11:16:16','2026-04-21 11:16:16'),(195,10,'Хирургическое удаление доброкачественного образования мягких тканей (липома, атерома)','hirurgicheskoe-udalenie-dobrokachestvennogo-obrazovaniya-myagkih-tkaney-lipoma-ateroma',90.49,30,'Хирургическое удаление доброкачественных образований мягких тканей (липом и атером) в медицинском центре «Маяк Здоровья» — это радикальный и надежный метод избавления от косметических дефектов и профилактики возможных осложнений.\n\nЛипома — это доброкачественное образование из жировой ткани. Растет она медленно, обычно её размер составляет около 2-3 см, однако в редких случаях может достигать 10 см и более. Липома представляет собой косметический дефект, а при значительных размерах способна сдавливать окружающие ткани, сосуды и нервные окончания, вызывая дискомфорт и болевые ощущения. Липома не склонна к озлокачествлению, но требует удаления при росте, появлении симптомов сдавления или по эстетическим соображениям.\n\nАтерома — это киста сальной железы, которая образуется при закупорке её выводного протока. Она состоит из плотной капсулы и творожистого содержимого (кожное сало, клетки эпидермиса). Атерома часто появляется на волосистой части головы, лице, шее, спине, в подмышечных впадинах и паховой области. Образование склонно к воспалению и нагноению, что сопровождается болью, покраснением, отеком и повышением температуры тела. Даже при отсутствии воспаления атерома постепенно увеличивается в размерах и становится заметным косметическим недостатком. Важно понимать, что самостоятельно атерома не рассасывается, а консервативное лечение неэффективно.\n\nКак проходит хирургическое удаление:\nПроцедура проводится под местной анестезией в амбулаторных условиях. После обработки операционного поля антисептическим раствором врач выполняет разрез кожи над областью образования. Размер разреза зависит от величины липомы или атеромы и может составлять от нескольких миллиметров до нескольких сантиметров. Затем хирург остро и тупо выделяет образование вместе с капсулой (это критически важно для предотвращения рецидива), после чего рана промывается антисептиком и послойно ушивается. На кожу накладываются косметические швы, которые снимаются через 7-10 дней. Удаленное образование по желанию пациента может быть направлено на гистологическое исследование для подтверждения доброкачественной природы.\n\nДля постановки точного диагноза и определения оптимальной тактики оперативного лечения приглашаем на консультацию к хирургам медицинского центра «Маяк Здоровья». Красота и здоровье вашего тела в надёжных руках наших специалистов!','• Наличие липомы любого размера и локализации;\n• Рост липомы в динамике;\n• Сдавление окружающих тканей, сосудов или нервов липомой, сопровождающееся болью, онемением, нарушением функции;\n• Косметический дефект, причиняющий психологический дискомфорт;\n• Наличие атеромы (любого размера);\n• Воспаление или нагноение атеромы (требует срочного вмешательства);\n• Рецидивирующее воспаление атеромы в анамнезе;\n• Желание пациента удалить образование с профилактической или эстетической целью;\n• Подозрение на злокачественный характер образования (быстрый рост, изменение цвета, изъязвление).','• Обязательная предварительная консультация хирурга для осмотра образования, подтверждения диагноза и определения объема вмешательства;\n• За 7-10 дней до операции исключить прием препаратов, влияющих на свертываемость крови (аспирин, антикоагулянты, нестероидные противовоспалительные средства) — только по согласованию с лечащим врачом;\n• За 2-3 дня до процедуры исключить употребление алкоголя;\n• Накануне операции принять душ, вымыть голову (если образование расположено на волосистой части);\n• В день операции не наносить на кожу в зоне вмешательства косметические средства (кремы, лосьоны, дезодоранты);\n• Надеть чистое, удобное бельё и одежду, обеспечивающую легкий доступ к зоне операции;\n• Сообщить врачу о наличии аллергических реакций, особенно на местные анестетики (лидокаин, новокаин);\n• Приём пищи в день операции не противопоказан, если не планируется внутривенная седация.\n\n','active',0,'2026-04-21 11:17:29','2026-04-21 11:17:29'),(196,16,'УЗИ сердца - оценка деформации миокарда (стрейн-эхокардиография)','uzi-serdca-ocenka-deformacii-miokarda-streyn-ehokardiografiya',109.55,30,'УЗИ сердца с оценкой деформации миокарда (стрейн-ЭХОКГ) — это расширенное ультразвуковое исследование сердца, которое позволяет выявить даже минимальные отклонения в работе сердечной мышцы уже на начальном этапе развития патологии. В отличие от стандартной эхокардиографии, данная методика дает возможность объективно оценить сократительную способность миокарда на уровне отдельных волокон.\n\nДля проведения ЭХО-кардиографии со Speckle tracking (спекл-трекинг) используется новейший ультразвуковой аппарат с дополнительным программным обеспечением, которое анализирует изменения рассеяния ультразвукового сигнала в тканях сердца. Технология отслеживает движение естественных акустических меток (спеклов) миокарда на протяжении сердечного цикла, что позволяет количественно оценить степень деформации (стрейн) сердечной мышцы.\n\nПреимущества исследования:\n• Раннее выявление сердечно-сосудистых заболеваний на доклинической стадии;\n• Спекл-трекинг определяет продольную деформацию левого желудочка, которая происходит раньше, чем поперечная. На стандартном УЗИ сердца оценить это изменение невозможно;\n• Позволяет оценить сократимость отдельных участков (сегментов) миокарда;\n• Дает возможность отличить физиологические адаптационные изменения в сердце от патологических (например, «спортивное сердце» от гипертрофической кардиомиопатии);\n• Позволяет спрогнозировать переносимость физических нагрузок при сердечной недостаточности и после перенесенного инфаркта миокарда;\n• Помогает оценить кардиотоксичность химиотерапевтических препаратов на самых ранних этапах;\n• Высокая воспроизводимость результатов и объективность оценки.\n\nКак проводится исследование:\nПроцедура проводится аналогично стандартному УЗИ сердца. Пациент располагается лёжа на левом боку или на спине. К грудной клетке прикрепляются электроды ЭКГ для синхронизации с сердечным циклом. Врач выполняет запись изображений сердца из стандартных доступов, после чего полученные данные автоматически обрабатываются специальной программой, которая рассчитывает показатели деформации миокарда. Диагностика длится 30-40 минут.\n\nОграничения метода:\nПрименение спекл-трекинга ограничено у пациентов с нарушениями ритма сердца: тахикардией (частота сердечных сокращений более 100 ударов в минуту), мерцательной аритмией, частой экстрасистолией, фибрилляцией предсердий или желудочков. В этих случаях точность оценки деформации миокарда может быть снижена из-за нерегулярности сердечных сокращений.','• Онкологические пациенты, проходящие или проходившие химиотерапию (особенно препаратами антрациклинового ряда, трастузумабом) — для раннего выявления кардиотоксичности и деформации миокарда. Результаты позволяют врачу-онкологу своевременно принять решение о необходимости коррекции схемы лечения;\n• Пациенты с пороками сердца (врожденными и приобретенными);\n• Ишемическая болезнь сердца;\n• Артериальная гипертензия;\n• Миокардиты и кардиомиопатии различного генеза;\n• Хроническая обструктивная болезнь лёгких (ХОБЛ) и бронхиальная астма;\n• Сахарный диабет;\n• Ревматоидный артрит и другие системные заболевания соединительной ткани;\n• Перенесенный COVID-19 (для оценки постковидного поражения миокарда);\n• Эндокринные заболевания (гипотиреоз, гипертиреоз, акромегалия, феохромоцитома);\n• Спортсмены с регулярной интенсивной нагрузкой на сердечно-сосудистую систему — для дифференциальной диагностики «спортивного сердца», подбора оптимального режима тренировок и прогнозирования функционального резерва;\n• Пациенты после инфаркта миокарда — для оценки жизнеспособности миокарда и прогноза;\n• Сердечная недостаточность — для оценки сократительной функции и прогнозирования течения заболевания.','• Специальной подготовки не требуется;\n• За 2-3 часа до исследования исключить интенсивные физические нагрузки;\n• За 1 час до процедуры воздержаться от курения и употребления кофеинсодержащих напитков (крепкий чай, кофе, энергетики);\n• Принять плановые лекарственные препараты, если иное не рекомендовано врачом;\n• Надеть удобную одежду, обеспечивающую легкий доступ к грудной клетке;\n• Взять с собой результаты предыдущих УЗИ сердца, ЭКГ, холтеровского мониторирования (при наличии).','active',0,'2026-04-21 11:19:23','2026-04-21 11:19:23'),(197,16,'УЗИ сердца - Эхокардиография','uzi-serdca-ehokardiografiya',68.59,30,'Эхокардиография (УЗИ сердца) с допплерографией — это современный, высокоинформативный и абсолютно безопасный метод ультразвуковой диагностики, позволяющий выявить врожденные и приобретенные патологии сердца, оценить его структуру и функциональное состояние. Процедура является безвредной, безболезненной и не занимает много времени, что делает её доступной для пациентов любого возраста, включая пожилых людей, маленьких детей и беременных женщин.\n\nВ медицинском центре «Маяк Здоровья» для исследования сердечно-сосудистой системы используется новейшее профессиональное оборудование экспертного класса, оснащенное опциями цветового допплеровского картирования и тканевой допплерографии. Это позволяет провести комплексную диагностику с высокой степенью точности.\n\nЧто позволяет оценить эхокардиография с допплерографией:\n• Врожденные и приобретенные пороки сердца;\n• Нарушения функции клапанного аппарата (стеноз, недостаточность, пролапс);\n• Наличие внутрисердечных тромбов и аневризм;\n• Состояние стенок и камер сердца (толщина миокарда, размеры предсердий и желудочков);\n• Скорости и направление кровотока в полостях сердца и крупных сосудах;\n• Состояние насосной (сократительной) функции сердца (фракция выброса);\n• Наличие опухолей сердца;\n• Признаки перенесенного инфаркта миокарда;\n• Состояние перикарда (наличие выпота, утолщения).\n\nИсходя из показаний приборов, врач дает точную оценку структурным и функциональным параметрам сердца, после чего оформляет заключение и предоставляет его пациенту. Полученные результаты сравниваются с общепринятыми нормами, выявленные отклонения подробно описываются в заключении. С результатами исследования пациент направляется к профильному специалисту — терапевту, кардиологу или неврологу — для составления плана дальнейшего лечения, если оно требуется.\n\nСвоевременное обследование позволяет выявить и предотвратить развитие серьезных сердечно-сосудистых заболеваний. Главное — вовремя обратиться в медицинское учреждение и сделать УЗИ сердца.','Эхокардиография рекомендуется при наличии следующих симптомов и состояний:\n• Нарушения сердечного ритма (ощущение перебоев в работе сердца, учащенное или замедленное сердцебиение);\n• Слабость, головокружение и повышенная утомляемость;\n• Боль, дискомфорт или ощущение тяжести в области сердца;\n• Одышка при физической нагрузке или в покое;\n• Синюшный оттенок кожи носогубного треугольника (цианоз);\n• Выраженные отеки нижних конечностей;\n• Повышение артериального давления;\n• Шумы в сердце, выявленные при аускультации;\n• Подозрение на порок сердца;\n• Перенесенный инфаркт миокарда;\n• Подготовка к полостным операциям или другим сложным медицинским вмешательствам;\n• Профессиональная деятельность, связанная со стрессами или тяжелыми физическими нагрузками (спортсмены, военнослужащие, спасатели);\n• Профилактическое обследование (рекомендуется проходить регулярно, особенно после 40 лет);\n• Контроль эффективности лечения сердечно-сосудистых заболеваний;\n• Наличие хронических заболеваний: сахарный диабет, гипертоническая болезнь, заболевания щитовидной железы, системные заболевания соединительной ткани.','• Специальной подготовки для проведения эхокардиографии не требуется;\n• Накануне исследования врач может рекомендовать воздержаться от приема седативных (успокаивающих) средств, так как они могут влиять на сердечный ритм;\n• За 2-3 часа до процедуры исключить интенсивные физические нагрузки;\n• За 1 час до исследования воздержаться от курения и употребления кофеинсодержащих напитков (крепкий чай, кофе, энергетики);\n• Принять плановые лекарственные препараты, если иное не рекомендовано врачом;\n• Надеть удобную одежду, обеспечивающую легкий доступ к грудной клетке;\n• Взять с собой результаты предыдущих УЗИ сердца, ЭКГ, холтеровского мониторирования (при наличии).','active',0,'2026-04-21 11:20:06','2026-04-21 11:20:06'),(198,18,'Электрокардиограмма','elektrokardiogramma',17.07,30,'Электрокардиограмма (ЭКГ) — это простой, универсальный и широко доступный метод инструментальной диагностики, позволяющий зарегистрировать электрическую активность сердца в момент проведения исследования. ЭКГ является базовым, но при этом чрезвычайно информативным способом оценки работы сердечно-сосудистой системы, который применяется как для первичной диагностики, так и для динамического наблюдения за состоянием пациента.\n\nВ основе метода лежит регистрация электрических потенциалов, возникающих в сердечной мышце во время её сокращения и расслабления. Эти сигналы улавливаются электродами, размещенными на коже пациента, усиливаются и преобразуются в графическую кривую — электрокардиограмму. Анализируя форму, амплитуду и продолжительность зубцов и интервалов, врач может оценить функцию автоматизма, проводимости, возбудимости и сократимости миокарда.\n\nЧто можно обнаружить с помощью ЭКГ:\n• Нарушения ритма сердца: тахикардию (учащенное сердцебиение), брадикардию (замедленное сердцебиение), экстрасистолию (внеочередные сокращения), мерцательную аритмию (фибрилляцию предсердий), трепетание предсердий;\n• Нарушения проводимости (блокады различной локализации и степени);\n• Ишемическую болезнь сердца, в том числе признаки острой или перенесенной ишемии миокарда;\n• Признаки инфаркта миокарда (острого, подострого, рубцовых изменений);\n• Гипертрофию (утолщение стенок) различных отделов сердца;\n• Признаки перегрузки камер сердца;\n• Электролитные нарушения (изменения уровня калия, кальция в крови);\n• Признаки воспалительных заболеваний сердца (миокардит, перикардит);\n• Оценку эффективности проводимого лечения (антиаритмического, антиангинального);\n• Контроль работы установленного электрокардиостимулятора.\n\nПроцедура является абсолютно безболезненной, неинвазивной, не имеет противопоказаний и может выполняться пациентам любого возраста, включая новорожденных и беременных женщин.\n\nКак проводится ЭКГ в медицинском центре «Маяк Здоровья»:\nЭлектрокардиограмма проводится по предварительной записи. Пациент располагается лёжа на спине на кушетке. На кожу в области грудной клетки, запястий и лодыжек накладываются электроды (одноразовые или многоразовые). Для улучшения контакта и проводимости сигнала на кожу наносится специальный гель. Запись ЭКГ занимает несколько минут, во время которых пациенту необходимо лежать спокойно, расслабившись и не двигаясь. Сразу после окончания процедуры врач проводит расшифровку и выдает заключение с графической лентой ЭКГ на руки пациенту.','Электрокардиограмма рекомендуется в следующих случаях:\n• Боли, дискомфорт, чувство тяжести или жжения в области сердца;\n• Ощущение перебоев в работе сердца, «замирания», «кувыркания»;\n• Учащенное или замедленное сердцебиение;\n• Одышка, нехватка воздуха;\n• Головокружение, предобморочные состояния, обмороки;\n• Повышение артериального давления;\n• Повышенная утомляемость, слабость;\n• Профилактическое обследование (в рамках диспансеризации, перед оперативными вмешательствами);\n• Возраст старше 40 лет (рекомендуется ежегодно);\n• Наличие хронических заболеваний: гипертоническая болезнь, сахарный диабет, заболевания щитовидной железы, ожирение;\n• Профессиональные вредности, высокий уровень стресса, интенсивные физические нагрузки;\n• Контроль эффективности лечения сердечно-сосудистых заболеваний;\n• Перенесенные инфекционные заболевания, способные давать осложнения на сердце (ангина, грипп, COVID-19).','• Специальной подготовки не требуется;\n• За 2-3 часа до исследования исключить интенсивные физические нагрузки;\n• За 1-2 часа до процедуры воздержаться от курения и употребления кофеинсодержащих напитков (крепкий чай, кофе, энергетики);\n• Принять плановые лекарственные препараты, если иное не рекомендовано врачом;\n• Надеть удобную одежду, обеспечивающую легкий доступ к грудной клетке, запястьям и лодыжкам (женщинам рекомендуется избегать колготок и чулок);\n• Непосредственно перед процедурой желательно отдохнуть в течение 5-10 минут;\n• Мужчинам с выраженным волосяным покровом на груди рекомендуется провести бритье грудной клетки для лучшего контакта электродов (может быть выполнено непосредственно перед процедурой медицинским персоналом);\n• Взять с собой результаты предыдущих ЭКГ (при наличии) для оценки динамики.','active',0,'2026-04-21 11:21:22','2026-04-21 11:21:22'),(199,18,'Холтеровское мониторирование ЭКГ','holterovskoe-monitorirovanie-ekg',58.58,30,'Холтеровское мониторирование ЭКГ (суточное мониторирование ЭКГ по Холтеру) — это метод длительной непрерывной регистрации электрокардиограммы пациента в течение 24 часов (суток) в условиях его обычной повседневной жизни. В отличие от стандартной ЭКГ, которая фиксирует работу сердца лишь в конкретный момент, холтеровское мониторирование позволяет оценить сердечную деятельность на протяжении длительного времени, зафиксировать эпизодические нарушения, которые могут не проявляться во время кратковременной записи.\n\nДля чего делают суточное мониторирование ЭКГ по Холтеру:\n\n1. Оценка ритма сердца. То, что пациент субъективно ощущает как сердцебиение, «замирание» или «перебои» в работе сердца, в реальности может оказаться проявлением различных нарушений ритма:\n• Экстрасистолия (внеочередные сокращения сердца);\n• Атриовентрикулярная блокада (нарушение проведения электрического импульса);\n• Пароксизмальная тахикардия (эпизоды учащенного пульса);\n• Брадикардия (эпизоды замедления пульса);\n• Фибрилляция предсердий (мерцательная аритмия);\n• Жизнеугрожающие аритмии.\n\nУ ряда пациентов аритмия может протекать абсолютно бессимптомно, и холтеровское мониторирование является единственным способом обнаружить данную патологию.\n\n2. Оценка эпизодов ишемии миокарда. Холтер помогает зафиксировать эпизоды недостаточного поступления кислорода к сердечной мышце и назначить правильное лечение пациентам с безболевой (немой) ишемией миокарда. Вовремя не диагностированная ишемия миокарда может привести к развитию инфаркта миокарда и представляет опасность для жизни пациента.\n\n3. Оценка работы сердца в привычных условиях жизни и при нагрузке. Суточная запись ЭКГ фиксирует, как реагирует сердце во время работы, отдыха, физических тренировок, сна, эмоциональных переживаний и стрессовых ситуаций.\n\n4. Оценка эффективности проводимого лечения. Метод позволяет объективно оценить действие антиаритмических, антиангинальных и гипотензивных препаратов.\n\n5. Контроль работы установленного электрокардиостимулятора.\n\nПреимущества холтеровского мониторирования ЭКГ:\n• Длительная оценка ритма сердца и его кровоснабжения в условиях обычной жизнедеятельности;\n• Объективный способ оценить ритм сердца благодаря непрерывной записи;\n• Возможность выявить связь между симптомами и изменениями на ЭКГ;\n• Оценка влияния физических и психоэмоциональных нагрузок на работу сердца;\n• Выявление безболевой ишемии миокарда при отсутствии болевых ощущений;\n• Оценка циркадных (суточных) изменений сердечного ритма.\n\nКак проводится холтеровское мониторирование ЭКГ:\nХолтер представляет собой компактный портативный регистратор электрокардиограммы, который соединяется с одноразовыми электродами, закрепленными на грудной клетке пациента. Прибор практически незаметен под одеждой и фиксируется на теле с помощью специального пояса или ремня. Установка и снятие аппарата производятся примерно в одно и то же время, чтобы общая продолжительность записи составила 23-24 часа.\n\nНакануне установки холтера мужчинам рекомендуется сбрить волосяной покров с грудной клетки для лучшей фиксации электродов.\n\nВ течение суток пациенту необходимо вести дневник, в котором отмечаются:\n• Время приема лекарственных препаратов;\n• Время приема пищи;\n• Периоды физической активности (ходьба, подъем по лестнице, спорт);\n• Периоды отдыха и сна;\n• Стрессовые ситуации, эмоциональные переживания;\n• Возникновение симптомов (боль в груди, сердцебиение, головокружение, одышка).\n\nСмена видов деятельности позволяет максимально полно оценить работу сердца в различных условиях. В зависимости от самочувствия пациента, врач может рекомендовать выполнение определенных нагрузок (подъем по лестнице, ходьба в быстром темпе), время выполнения которых обязательно фиксируется в дневнике.\n\nПосле снятия регистратора врач скачивает запись в специальную компьютерную программу, проводит анализ полученной информации, сопоставляет данные ЭКГ с записями в дневнике пациента и формирует заключение.','Холтеровское мониторирование ЭКГ назначается врачом (терапевтом, кардиологом, эндокринологом, неврологом) при следующих состояниях:\n• Жалобы на перебои в работе сердца, ощущение «замирания» или «кувыркания»;\n• Приступы учащенного сердцебиения;\n• Эпизоды потери сознания, предобморочные состояния, головокружения неясного генеза;\n• Одышка, не связанная с заболеваниями дыхательной системы;\n• Боли в области сердца неясного происхождения;\n• Подозрение на безболевую ишемию миокарда;\n• Диагностика и контроль эффективности лечения нарушений ритма сердца;\n• Оценка работы установленного электрокардиостимулятора;\n• Комплексное обследование пациентов с артериальной гипертензией, сахарным диабетом, заболеваниями щитовидной железы;\n• Обследование пациентов после перенесенного инфаркта миокарда;\n• Оценка сердечного ритма у пациентов с синдромом обструктивного апноэ сна;\n• Профилактическое обследование лиц с высоким риском сердечно-сосудистых заболеваний.','• Специальной подготовки не требуется;\n• Накануне установки холтера мужчинам рекомендуется сбрить волосяной покров с грудной клетки для обеспечения надежного контакта электродов с кожей;\n• В день установки принять душ, так как во время ношения прибора мочить его и принимать водные процедуры нельзя;\n• Надеть удобную одежду, под которой можно комфортно разместить регистратор (желательно хлопчатобумажную, не синтетическую, во избежание накопления статического электричества);\n• Женщинам рекомендуется надеть бюстгальтер для дополнительной фиксации электродов и проводов;\n• Принять плановые лекарственные препараты, если иное не рекомендовано врачом (сделать отметку в дневнике);\n• Взять с собой ручку и дневник (выдается в медицинском центре) для фиксации событий в течение суток.','active',0,'2026-04-21 11:22:42','2026-04-21 11:22:42'),(200,1,'Консультация врача-терапевта','konsultaciya-vracha-terapevta',44.66,30,'Терапия — это первый уровень медицинской помощи, область медицины, с которой начинается обследование и лечение у большинства пациентов. Врач-терапевт является специалистом широкого профиля, который обладает знаниями о проявлениях различных заболеваний внутренних органов и систем: дыхательной, сердечно-сосудистой, пищеварительной, мочевыделительной, иммунной, нервной системы, опорно-двигательного аппарата. Именно поэтому обратиться на консультацию к терапевту можно практически с любой проблемой.\n\nВ клинике экспертной медицины «Маяк Здоровья» пациентов консультируют и лечат терапевты с многолетним опытом работы с различными заболеваниями. Специалисты клиники обеспечивают высокий уровень медицинской помощи, проводят диагностику и лечение в строгом соответствии с актуальными клиническими протоколами, применяя персонализированный подход к каждому пациенту.\n\nОсновные задачи врача-терапевта:\n• Сбор жалоб и детализация симптомов;\n• Сбор анамнеза заболевания и жизни пациента;\n• Проведение общего осмотра (оценка состояния кожных покровов, видимых слизистых, измерение артериального давления, частоты пульса, частоты дыхания, аускультация легких и сердца, пальпация живота);\n• Назначение необходимого объема лабораторных и инструментальных исследований;\n• Интерпретация результатов обследования;\n• Постановка предварительного или окончательного диагноза;\n• Назначение медикаментозного и немедикаментозного лечения;\n• При необходимости — направление к узким специалистам (кардиологу, гастроэнтерологу, пульмонологу, эндокринологу, неврологу и др.);\n• Оформление медицинской документации, выдача листков нетрудоспособности, справок, рецептов;\n• Динамическое наблюдение за пациентами с хроническими заболеваниями;\n• Профилактическое консультирование, направленное на предотвращение развития заболеваний.\n\nОтдельное и важное направление современной терапии — наблюдение и лечение пациентов, перенесших COVID-19. Постковидные остаточные явления и осложнения (слабость, одышка, снижение толерантности к физическим нагрузкам, когнитивные нарушения, изменения со стороны сердечно-сосудистой системы) требуют особого внимания и своевременной коррекции. Врачи-терапевты клиники «Маяк Здоровья» имеют необходимый опыт ведения таких пациентов и помогут восстановить здоровье после перенесенной инфекции.\n\nТерапия в «Маяке Здоровья» — это сочетание профессионализма, внимательного отношения и современных методов диагностики и лечения.','Консультация врача-терапевта рекомендуется при появлении следующих симптомов и состояний:\n• Общее недомогание, слабость, быстрая утомляемость;\n• Повышение температуры тела (длительное или периодическое);\n• Головная боль, головокружение;\n• Кашель (острый или хронический), одышка, боль в грудной клетке;\n• Насморк, боль в горле, заложенность носа;\n• Боль в животе, изжога, отрыжка, тошнота, рвота, нарушение стула;\n• Повышение или понижение артериального давления;\n• Отеки различной локализации;\n• Боли в суставах и мышцах;\n• Изменение массы тела (необъяснимое похудение или набор веса);\n• Профилактический осмотр (диспансеризация);\n• Оформление санаторно-курортной карты, справок;\n• Получение направления к узким специалистам;\n• Состояние после перенесенной коронавирусной инфекции (COVID-19);\n• Наличие хронических заболеваний, требующих регулярного наблюдения (гипертоническая болезнь, сахарный диабет, хронический бронхит и др.).','Специальной подготовки для консультации врача-терапевта не требуется. Для более эффективного приема рекомендуется:\n• Сформулировать четкий перечень жалоб и вопросов к врачу;\n• Подготовить список принимаемых лекарственных препаратов с указанием дозировок и кратности приема;\n• Взять с собой имеющиеся результаты предыдущих обследований (анализы крови и мочи, ЭКГ, УЗИ, рентген, флюорография, выписки из стационаров, заключения других специалистов);\n• Надеть удобную одежду, обеспечивающую легкий доступ для осмотра (измерение давления, аускультация легких и сердца);\n• При планируемом осмотре живота желательно не принимать пищу за 1-2 часа до приема.','active',0,'2026-04-21 11:24:09','2026-04-21 11:24:09'),(201,23,'Консультация врача-хирурга (флеболога)','konsultaciya-vracha-hirurga-flebologa',42.66,30,'Консультация флеболога — это прием специалиста, который занимается диагностикой, лечением и профилактикой заболеваний венозной системы. Флеболог помогает пациентам справиться с патологиями вен нижних конечностей, а также другими нарушениями венозного кровообращения.\n\nСамая частая причина обращений к этому специалисту — варикозная болезнь вен нижних конечностей. Больше других ей подвержены представители профессий, связанных с длительным статическим пребыванием в положении стоя или сидя: учителя, хирурги, парикмахеры, продавцы, офисные работники, водители. Также факторами риска являются наследственная предрасположенность, беременность, избыточная масса тела, малоподвижный образ жизни.\n\nБолезни вен опасны своими осложнениями: тромбофлебит, тромбоз глубоких вен, трофические язвы, кровотечения из варикозно расширенных вен, тромбоэмболия легочной артерии. Поэтому не следует откладывать визит к врачу при появлении первых симптомов и заниматься самолечением.\n\nКак проходит консультация флеболога:\n• Врач тщательно собирает анамнез заболевания и жизни пациента, уточняет жалобы, выясняет наличие факторов риска;\n• Проводит визуальный осмотр нижних конечностей в положении стоя и лежа;\n• Выполняет пальпацию вен и окружающих тканей;\n• Проводит функциональные пробы для оценки состояния венозных клапанов;\n• При необходимости назначает дополнительное инструментальное обследование (УЗИ вен нижних конечностей с допплерографией — дуплексное сканирование);\n• На основании полученных данных устанавливает диагноз, определяет стадию заболевания;\n• Обсуждает с пациентом возможные варианты лечения (консервативное, компрессионное, склеротерапия, лазерная коагуляция, хирургическое);\n• Дает рекомендации по образу жизни, питанию, физической активности, подбирает компрессионный трикотаж;\n• Составляет индивидуальный план лечения и наблюдения.\n\nВ клинике экспертной медицины «Маяк Здоровья» специалисты позаботятся о красоте и здоровье ваших ног, применяя современные методы диагностики и лечения венозной патологии.','Консультация флеболога рекомендуется при наличии следующих симптомов и состояний:\n• Тяжесть, распирание или боль в ногах, усиливающиеся к вечеру или после длительного пребывания в положении стоя или сидя;\n• Расширенные и извитые поверхностные вены, появление сосудистых «звездочек» (телеангиэктазий), уплотнений и венозных узлов;\n• Отеки нижних конечностей (особенно к вечеру, проходящие после ночного отдыха);\n• Ночные судороги в икроножных мышцах;\n• Гиперпигментация (потемнение) кожи в области голеней и лодыжек, покраснение, уплотнение кожи;\n• Зуд, жжение в области нижних конечностей;\n• Появление трофических язв или предъязвенного состояния кожи;\n• Сильная усталость и дискомфорт в ногах после длительного нахождения в вертикальном положении;\n• Наследственная предрасположенность к варикозной болезни;\n• Планирование беременности при наличии факторов риска варикозной болезни;\n• Профессиональная деятельность, связанная с длительными статическими нагрузками на ноги;\n• Профилактический осмотр для раннего выявления венозной патологии;\n• Подбор компрессионного трикотажа (профилактического или лечебного).','Специальной подготовки для консультации флеболога не требуется. Для максимально информативного осмотра рекомендуется:\n• Надеть удобную одежду и обувь, обеспечивающую легкий доступ для осмотра нижних конечностей до уровня паховых складок (юбка, шорты, свободные брюки);\n• Не наносить на кожу ног косметические средства (кремы, лосьоны, масла) в день приема;\n• Взять с собой результаты предыдущих обследований (УЗИ вен нижних конечностей, анализы крови) и заключения других специалистов (при наличии);\n• Составить список принимаемых лекарственных препаратов (особенно гормональных контрацептивов, антикоагулянтов);\n• Сообщить врачу о наличии аллергических реакций, хронических заболеваний, перенесенных операциях, беременностях и родах.','active',0,'2026-04-21 11:25:29','2026-04-21 11:25:29'),(202,23,'Пенная склеротерапия','pennaya-skleroterapiya',94.53,30,'Пенная склеротерапия (Foam-form склеротерапия) — это современный малоинвазивный метод лечения варикозной болезни нижних конечностей, основанный на введении в пораженную вену специального склерозирующего препарата, преобразованного в пенную форму. Данный метод является эффективной альтернативой традиционному хирургическому вмешательству и подходит для лечения варикозно расширенных вен различного диаметра, включая магистральные стволы и крупные притоки. Для определения возможности применения данного метода лечения именно в вашем случае необходима предварительная консультация врача-флеболога.\n\nКак проводится процедура:\nДля получения пены жидкий склерозант непосредственно перед введением смешивается с воздухом или специальным газом в определенной пропорции с помощью специального устройства или шприцевого метода. Полученная мелкодисперсная пена вводится в просвет варикозной вены через тонкую иглу. Процедура проводится под обязательным ультразвуковым контролем (дуплексным сканированием), что обеспечивает точность введения препарата, визуализацию распространения пены по вене и контроль за полнотой облитерации сосуда. После введения пена вытесняет кровь из вены и вступает в контакт с внутренней стенкой сосуда (эндотелием), вызывая контролируемое химическое повреждение. В результате этого процесса происходит облитерация (склеивание, спадание) вены, и со временем она превращается в соединительнотканный тяж, который впоследствии полностью рассасывается. Кровоток перераспределяется по здоровым глубоким венам. Продолжительность процедуры составляет от 15 до 40 минут в зависимости от объема вмешательства.\n\nПреимущества пенной склеротерапии:\n• Пена не смешивается с кровью, а выталкивает её из сосуда, благодаря чему вена становится пустой, и достигается максимальный контакт препарата со стенкой сосуда;\n• Пена вызывает выраженный и продолжительный спазм вены: её диаметр может уменьшаться до 5 раз, что повышает эффективность склерозирования;\n• По сравнению с жидким склерозантом, пена значительно дольше воздействует на стенку сосуда, что позволяет использовать меньшее количество препарата для достижения стойкого результата;\n• Процедура является амбулаторной и не требует госпитализации в стационар;\n• Практически безболезненна, ощущения сравнимы с обычной внутривенной инъекцией;\n• Дает отличный косметический эффект: исчезают видимые варикозные вены, не остается послеоперационных рубцов и шрамов;\n• Короткий период восстановления: в большинстве случаев пациент возвращается к привычному образу жизни сразу после процедуры;\n• Минимальный риск осложнений при правильном выполнении.\n\nПосле процедуры:\nСразу после завершения пенной склеротерапии на ногу надевается компрессионный трикотаж (специальные чулки или гольфы) или накладывается эластичная компрессионная повязка. В течение 20-30 минут пациенту рекомендуется оставаться в медицинском центре под наблюдением персонала для контроля общего самочувствия и исключения возможных немедленных реакций. Перед уходом пациент получает от флеболога подробные индивидуальные рекомендации по дальнейшему режиму, ношению компрессионного трикотажа, физической активности и ответы на все интересующие вопросы.','Пенная склеротерапия может быть рекомендована в следующих случаях:\n• Варикозная болезнь нижних конечностей (в том числе стволовая форма, несостоятельность перфорантных вен);\n• Ретикулярный варикоз и телеангиэктазии (сосудистые «звездочки»);\n• Варикозное расширение притоков магистральных подкожных вен;\n• Рецидив варикозной болезни после хирургического лечения;\n• Врожденные венозные мальформации;\n• Венозные озера и ангиомы.\n\nОкончательное решение о целесообразности и возможности проведения пенной склеротерапии принимает врач-флеболог после проведения осмотра и ультразвукового дуплексного сканирования вен нижних конечностей.','• Обязательная предварительная консультация флеболога с проведением УЗИ вен нижних конечностей (дуплексного сканирования) для оценки состояния венозной системы и определения показаний к процедуре;\n• За 2-3 дня до процедуры исключить прием алкоголя;\n• За сутки до процедуры не использовать косметические средства (кремы, лосьоны, масла) на коже ног;\n• В день процедуры принять душ, надеть чистое бельё;\n• Надеть удобную одежду и обувь, не стесняющую движений;\n• Иметь при себе компрессионный трикотаж (чулки или гольфы), рекомендованный флебологом;\n• Легкий прием пищи не позднее чем за 2 часа до процедуры;\n• Сообщить врачу о принимаемых лекарственных препаратах, особенно о средствах, влияющих на свертываемость крови (антикоагулянты, аспирин), и гормональных препаратах;\n• Сообщить врачу о наличии аллергических реакций, особенно на лекарственные препараты;\n• Женщинам рекомендуется проводить процедуру вне периода менструации.','active',0,'2026-04-21 11:26:38','2026-04-21 11:26:38'),(203,2,'Консультация врача-кардиолога','konsultaciya-vracha-kardiologa',44.66,30,'Кардиолог — это специалист, который занимается профилактикой, диагностикой и лечением патологий сердечно-сосудистой системы.\n\nС какими заболеваниями пациенты обращаются к кардиологу:\n• Инфаркт миокарда;\n• Ишемическая болезнь сердца;\n• Стенокардия;\n• Аритмии;\n• Сердечная недостаточность;\n• Травмы области сердца;\n• Пороки сердца: врожденные и приобретенные;\n• Атеросклероз;\n• Артериальная гипотензия;\n• Артериальная гипертензия;\n• И некоторые другие заболевания.\n\nФакторы риска развития сердечно-сосудистой патологии:\n• Наследственность;\n• Мужской пол;\n• Возраст;\n• Повышенный уровень холестерина в крови;\n• Артериальная гипертензия;\n• Курение;\n• Малоподвижный образ жизни;\n• Избыточная масса тела;\n• Сахарный диабет;\n• Стресс.\n\nКак проходит консультация: кардиолог собирает анамнез, проводит осмотр, измеряет артериальное давление, проверяет пульс. При необходимости врач направляет на дополнительные обследования: ЭКГ, УЗИ сердца, холтеровское мониторирование, суточное мониторирование артериального давления и другие.','• Боли в области сердца или за грудиной;\n• Отёки на нижних конечностях;\n• Одышка, удушье, чувство нехватки воздуха;\n• Низкая переносимость физических нагрузок;\n• Нарушение ритма сердца;\n• Слабость, быстрая утомляемость;\n• Высокое или низкое артериальное давление;\n• Сердечно-сосудистая патология у близких родственников;\n• Эпизоды потери сознания.','Специальной подготовки не требуется. Обязательно возьмите с собой на приём результаты предыдущих осмотров и обследований.','active',0,'2026-04-21 11:28:07','2026-04-21 11:28:07'),(204,15,'Консультация врача-гастроэнтеролога','konsultaciya-vracha-gastroenterologa',49.66,30,'Гастроэнтерология — область медицины, которая занимается диагностикой и лечением заболеваний органов желудочно-кишечного тракта. Внимание и забота о пищеварительной системе — основа здоровья всего организма.\n\nВ клинике «Маяк Здоровья» оказываются следующие услуги:\n• Консультация врача-гастроэнтеролога.','• Боли и дискомфорт в животе;\n• Изжога, отрыжка, горечь во рту;\n• Тошнота, рвота;\n• Нарушения стула (запоры, диарея);\n• Вздутие живота, метеоризм;\n• Тяжесть после еды;\n• Снижение или повышение аппетита;\n• Необъяснимое изменение веса;\n• Профилактическое обследование органов ЖКТ.','Рекомендации по подготовке к консультации гастроэнтеролога уточняйте при записи. При наличии результатов предыдущих обследований (ФГДС, УЗИ, анализы) возьмите их с собой на прием.\n\n','active',0,'2026-04-21 11:31:00','2026-04-21 11:31:00'),(205,3,'Консультация врача-невролога','konsultaciya-vracha-nevrologa',44.66,30,'Невролог — это врач, который проводит диагностику и занимается лечением патологий головного и спинного мозга, а также периферических нервов.\n\nНа консультации врач собирает подробный анамнез, изучает результаты анализов и обследований, проводит осмотр, при необходимости назначает дополнительные обследования и составляет план лечения. Невролог проверяет чувствительность кожи и наличие тремора, тонус и силу мышц, точность движений, оценивает рефлексы, устойчивость при стоянии и ходьбе.\n\nНеврологи клиники владеют лечебными блокадами: паравертебральной, эпидуральной, триггерных точек, грушевидной мышцы.','• Боль и дискомфорт в области шеи и/или спины;\n• Головные боли различной интенсивности;\n• Болезненные ощущения в области лица;\n• Слабость в мышцах рук и ног;\n• Судороги;\n• Панические атаки;\n• Онемение верхней или нижней конечности;\n• Поражение нервной системы при сахарном диабете;\n• Проблемы с ориентацией в пространстве;\n• Неустойчивая походка, нарушение координации;\n• Снижение памяти;\n• Тремор рук;\n• Проблемы с речью;\n• Постоянная усталость и снижение работоспособности;\n• Нервные тики;\n• Эпизоды потери сознания в анамнезе;\n• Бессонница;\n• Состояние после травмы головы или позвоночного столба.','Специальной подготовки не требуется. Не забудьте взять с собой на прием результаты предыдущих медицинских осмотров и обследований.','active',0,'2026-04-21 11:31:51','2026-04-21 11:31:51'),(206,3,'Паравертебральная блокада','paravertebralnaya-blokada',29.98,30,'Блокада грушевидной мышцы выполняется при наличии у пациента синдрома грушевидной мышцы. При этой патологии боль локализуется в области ягодицы и отдаёт в нижнюю конечность. Боль усиливается при длительном нахождении в одном положении, особенно в положении сидя. В основе синдрома лежит спазм грушевидной мышцы, который приводит к сдавлению седалищного нерва.\n\nБлокаду осуществляет врач после точного определения места инъекции путем разметки на коже. Для процедуры используют шприц с длинной и тонкой иглой. Блокада протекает практически безболезненно, через 10-15 минут пациент ощущает исчезновение или значительное уменьшение боли.\n\nДля блокады используют анестетики (новокаин, лидокаин и другие), а также кортикостероиды, которые снимают отёк и обладают противовоспалительным действием.','• Синдром грушевидной мышцы;\n• Боль в ягодичной области с иррадиацией в нижнюю конечность;\n• Сдавление седалищного нерва вследствие спазма грушевидной мышцы;\n• Усиление боли при длительном сидении.','Перед процедурой необходима обязательная консультация специалиста для подтверждения диагноза и исключения противопоказаний.','active',0,'2026-04-21 11:32:41','2026-04-21 11:32:41'),(207,12,'Консультация врача-уролога, к.м.н','konsultaciya-vracha-urologa-kmn',65.66,30,'Консультация уролога — это прием специалиста, к которому обращаются мужчины с патологиями мочеполовой системы и женщины с болезнями мочевыделительной системы. Частые пациентки уролога — беременные с циститами, пиелонефритами, бессимптомной бактериурией.\n\nУролог лечит: цистит, везикулит, простатит, поликистоз почек, эректильную дисфункцию, пиелонефрит, ДГПЖ (аденому простаты), мочекаменную болезнь, а также другие заболевания.\n\nКонсультация включает сбор анамнеза, осмотр, назначение обследований и анализов, постановку диагноза и составление плана лечения. При необходимости операции уролог в доступной форме объяснит её суть.','• Частые позывы к мочеиспусканию;\n• Болезненное мочеиспускание с резями;\n• Мочеиспускание малыми порциями или полное его отсутствие;\n• Частые ночные походы в туалет;\n• Болезненные ощущения внизу живота, в поясничной области, в промежности;\n• Патологический анализ мочи, изменение её цвета, запаха, примесь крови или гноя;\n• Снижение либидо у мужчин, проблемы с эрекцией, нарушение эякуляции, отсутствие оргазма;\n• Бесплодие у мужчины;\n• Подбор мужских контрацептивов;\n• Ожирение, старение у мужчины.','Специальной подготовки не требуется. Рекомендуется взять с собой результаты предыдущих обследований и анализов (при наличии). За 1-1,5 часа до приема не опорожнять мочевой пузырь для возможности проведения УЗИ или сдачи анализов при необходимости.','active',0,'2026-04-21 11:33:35','2026-04-21 11:33:35'),(208,12,'Лечебный массаж предстательной железы','lechebnyy-massazh-predstatelnoy-zhelezy',26.62,30,'Массаж простаты — это механическое воздействие на предстательную железу указательным пальцем врача, вводимым в прямую кишку.\n\nЭффект массажа простаты:\n• Улучшает местный кровоток и лимфоотток;\n• Повышает обмен веществ;\n• Нормализует тонус гладкомышечной ткани простаты;\n• Повышает тонус мышц промежности;\n• Убирает застойные явления в простате;\n• Уменьшает болевой синдром;\n• Восстанавливает половую функцию и либидо.\n\nКак проходит процедура: пациент приходит с наполненным мочевым пузырем, ложится на правый бок и поджимает колени к животу. Врач надевает перчатку и вводит указательный палец в прямую кишку. Процедура должна быть безболезненной, степень надавливания регулируется по ощущениям пациента. Интенсивность массажа зависит от консистенции простаты: мягкая — лёгкие нажатия, плотная или твёрдая — более сильные. После массажа пациенту нужно помочиться. Длительность — 2 минуты. Курс — от 8 до 10 процедур с интервалом в 1-2 дня.','• Хронический простатит;\n• Эректильные расстройства;\n• Хроническая тазовая боль;\n• Получение секрета простаты для анализа.','• Прийти на прием с наполненным мочевым пузырем;\n• Предварительно опорожнить кишечник естественным путем;\n• Провести гигиенический туалет перианальной области.\n\nПротивопоказания\n• Острый простатит;\n• Кисты простаты;\n• Аденома простаты (ДГПЖ);\n• Рак простаты;\n• Геморрой;\n• Анальная трещина;\n• Воспаление прямой кишки;\n• Повышение температуры;\n• Острый уретрит;\n• Острая задержка мочеиспускания.','active',0,'2026-04-21 11:34:44','2026-04-21 11:34:44'),(209,24,'Консультация врача-нефролога','konsultaciya-vracha-nefrologa',44.66,30,'Консультация нефролога в клинике экспертной медицины проводится по предварительной записи. Прием ведет один из ведущих нефрологов Беларуси, ранее — главный внештатный нефролог Комитета по здравоохранению Мингорисполкома.\n\nНефролог занимается диагностикой, лечением и предотвращением заболеваний почек.\n\nНефролог лечит:\n• Мочекаменную болезнь;\n• Пиелонефрит;\n• Гломерулонефрит;\n• Амилоидоз;\n• Лекарственное поражение почек;\n• Вторичное поражение почек при сахарном диабете, артериальной гипертензии, системных заболеваниях соединительной ткани;\n• Хроническую почечную недостаточность.\n\nНефролог медицинского центра постоянно сотрудничает с эндокринологами, врачами ультразвуковой диагностики, урологами, кардиологами, что обеспечивает точную диагностику и эффективное лечение.\n\nКак проводится консультация нефролога:\n• Сбор жалоб с их детализацией;\n• Сбор анамнестических данных заболевания;\n• Выявление факторов риска заболеваний;\n• Интерпретация результатов клинико-лабораторных и инструментальных исследований;\n• Проведение общего осмотра;\n• Проведение пальпации, перкуссии, аускультации;\n• Установление клинико-функционального диагноза;\n• Определение тактики лечения и индивидуальных рекомендаций;\n• Назначение медикаментозного и немедикаментозного лечения;\n• Оформление медицинской документации и консультативного заключения.\n\nКак сохранить здоровье почек:\n• Отказаться от курения;\n• Избегать бесконтрольного приема токсичных для почек препаратов (НПВС, антибиотики, мочегонные);\n• Правильно питаться;\n• Контролировать вес;\n• Контролировать артериальное давление и уровень сахара в крови;\n• Уделять время физической активности.','• Боль в пояснице и/или при мочеиспускании;\n• Нарушение мочеиспускания;\n• Уменьшение или увеличение количества мочи;\n• Изменения в анализах мочи: появление белка и/или эритроцитов;\n• Макрогематурия: появление крови в моче, видимое глазом;\n• Изменение цвета или запаха мочи;\n• Отёки лица, век, ног;\n• Изменения в почках по УЗИ: отсутствие почки, маленькие размеры, поликистоз;\n• Артериальная гипертензия, устойчивая к лечению;\n• Приём лекарств, потенциально опасных для почек (НПВС, мочегонные);\n• Патология почек у беременных, планирование беременности.','Специальной подготовки не требуется. Взять с собой результаты предыдущих обследований и анализов (общий анализ мочи, биохимия крови, УЗИ почек).','active',0,'2026-04-21 11:35:46','2026-04-21 11:35:46'),(210,24,'Разработка индивидуального плана питания при болезни почек с учетом стадии заболевания','razrabotka-individualnogo-plana-pitaniya-pri-bolezni-pochek-s-uchetom-stadii-zabolevaniya',13.06,30,'Разработка индивидуального плана питания при болезни почек с учетом стадии заболевания — это персональный подбор диетических рекомендаций, адаптированных к конкретному диагнозу и актуальным потребностям пациента.\n\nВ рамках услуги проводится:\n• Оценка белково-энергетического состояния и коррекция рекомендованной нормы потребления белка;\n• Определение индивидуальных норм продуктов питания в зависимости от содержания в них веществ, подлежащих ограничению (калий, фосфор, кальций, натрий, пурины и др.);\n• Подбор примерного рациона с учетом индивидуальных пищевых предпочтений и потребностей пациента;\n• Устное информирование и выдача подробных письменных рекомендаций.','• Хроническая болезнь почек любой стадии;\n• Мочекаменная болезнь;\n• Пиелонефрит, гломерулонефрит;\n• Нарушение функции почек;\n• Необходимость коррекции питания при почечной патологии.','Взять с собой результаты анализов (креатинин, мочевина, калий, фосфор, кальций, общий анализ мочи), заключение нефролога с указанием стадии заболевания.','active',0,'2026-04-21 11:36:26','2026-04-21 11:36:26'),(211,25,'Консультация врача-онколога','konsultaciya-vracha-onkologa',42.66,30,'Консультация онколога — это прием специалиста, который занимается диагностикой, лечением и профилактикой доброкачественных и злокачественных образований.\n\nХорошее самочувствие не гарантирует отсутствия заболеваний. Многие онкозаболевания на ранних стадиях протекают без ярких симптомов, поэтому важно регулярно проходить комплексные медосмотры и при необходимости посещать онколога.\n\nДля злокачественных опухолей характерен быстрый бесконтрольный рост, разрушение окружающих тканей, появление метастазов и изменение структуры клеток.\n\nНа консультации онколог знакомится с результатами обследований, при необходимости назначает новые, ставит диагноз и предлагает варианты лечения.','• Кровь в моче или кале;\n• Частые носовые кровотечения;\n• Следы крови на белье;\n• Резкое снижение массы тела без объективных причин;\n• Появление на коже фибром, папиллом, кондилом, невусов (родинок) или изменение их формы, цвета, размера, появление кровоточивости;\n• Наличие уплотнений;\n• Увеличение лимфоузлов;\n• Частый и стремительный рост температуры;\n• Длительная боль или дискомфорт в одном месте (жжение, давление, тяжесть, першение);\n• Нарушение сна, бессонница;\n• Ухудшение зрения, памяти, слуха;\n• Продолжительные головные боли;\n• Необычные выделения: из уретры, сосков, прямой кишки, влагалища;\n• Беспричинная потеря аппетита, слабость, тошнота, усталость.','Специальной подготовки не требуется. Взять с собой результаты предыдущих обследований, анализов и заключений других специалистов (при наличии).','active',0,'2026-04-21 11:37:13','2026-04-21 11:37:13'),(212,26,'Консультация врача-онколога (маммолога) к.м.д., доцента','konsultaciya-vracha-onkologa-mammologa-kmd-docenta',42.66,30,'Врач-маммолог — это специалист, который занимается диагностикой и лечением заболеваний молочных желез (груди). Патологии молочных желез могут встречаться как у женщин, так и у мужчин.\n\nМаммолог занимается диагностикой и лечением широкого спектра заболеваний:\n• Воспалительные заболевания — разные формы маститов;\n• Мастопатия, фиброзно-кистозная болезнь, гинекомастия и др.;\n• Диагностика образований в молочных железах;\n• Последствия перенесенных травм.\n\nВажно помнить, что на ранних стадиях многие маммологические заболевания протекают бессимптомно, а в запущенных формах могут потребовать оперативного вмешательства и длительного лечения.\n\nОбязательные этапы комплексной диагностики груди для женщин от 18 до 35 лет:\n• УЗИ молочных желез;\n• Пальпаторная диагностика;\n• Консультация врача-маммолога по результатам обследований.\n\nПосле 35 лет женщинам рекомендуется ежегодно проходить также маммографию.','• Изменения размера, формы груди, соска или ареолы;\n• Боль в молочной железе;\n• Жжение, зуд;\n• Уплотнения в молочных железах;\n• Покраснение участков кожи в области груди;\n• Выделения из соска (при отсутствии лактации);\n• Травмы в области груди;\n• Профилактический осмотр (даже при отсутствии симптомов).','Специальной подготовки не требуется. Взять с собой результаты предыдущих обследований (УЗИ молочных желез, маммография) при наличии. Оптимальное время для визита — с 5 по 12 день менструального цикла.','active',0,'2026-04-21 11:38:14','2026-04-21 11:38:14'),(213,26,'Пункционная биопсия образования молочной железы','punkcionnaya-biopsiya-obrazovaniya-molochnoy-zhelezy',69.47,30,'Пункционная биопсия образования молочной железы — это диагностическая процедура, позволяющая определить природу образования (доброкачественное или злокачественное). Для визуальной диагностики используют УЗИ и маммографию, но только пункция дает точный ответ о характере клеток.\n\nКроме определения природы образования, пункция помогает ответить на вопросы:\n• Степень распространения заболевания;\n• Стадия развития;\n• Структура новообразования;\n• Является ли образование гормональным или воспалительным процессом.\n\nПосле пункции возможны временные явления: тошнота, головокружение, дискомфорт в месте прокола, незначительный отёк, кровоточивость раны. Эти симптомы быстро проходят.','• Пальпируемое объёмное образование в груди;\n• Непонятные изменения в области соска;\n• Язвы на груди;\n• Пятна на маммографии;\n• Подозрительные участки на УЗИ.','Противопоказания\n• Беременность и лактация;\n• Менструация;\n• Лихорадка;\n• Образование размером до 5 мм;\n• Аллергия на препараты для анестезии.\n\nРекомендации по подготовке уточняйте у врача. Процедура не проводится во время менструации. При наличии аллергии на анестетики сообщить врачу заранее.','active',0,'2026-04-21 11:39:35','2026-04-21 11:39:35'),(214,27,'Консультация врача-диетолога','konsultaciya-vracha-dietologa',44.57,30,'Диетология — это не всегда про похудение. Врач-диетолог занимается вопросами правильного и рационального питания для здоровых людей и тех, кто имеет хронические заболевания. Специалист решает задачи организации питания любой сложности.\n\nНаиболее частая причина обращения к диетологу — избыточная масса тела и ожирение. В большинстве случаев к диетологу приходят после строгих диет, отказ от которых приводит к стремительному набору веса.\n\nДругие вопросы, которые решает врач-диетолог:\n• Питание при дефиците массы тела;\n• Нарушение обменных процессов на фоне изменений гормонального статуса (эндокринологические заболевания, послеродовый период, менопауза);\n• Изменения в рационе на фоне резкого увеличения или приостановки физической активности;\n• Коррекция рациона питания при психоэмоциональных нагрузках;\n• Организация правильного питания для всей семьи.\n\nВ клинике принимает эксперт в области диетологии — сертифицированный врач с практическим опытом в эндокринологии и диетологии. Диетолог проводит подробный разбор возможных причин нарушений обмена веществ, дает рекомендации по их коррекции.','• Избыточная масса тела, ожирение;\n• Дефицит массы тела;\n• Нарушения обмена веществ;\n• Эндокринологические заболевания, требующие коррекции питания;\n• Послеродовый период, менопауза;\n• Изменение уровня физической активности;\n• Психоэмоциональные нагрузки;\n• Необходимость организации правильного питания для семьи;\n• Хронические заболевания, требующие диетического питания.','Специальной подготовки не требуется. Рекомендуется вести дневник питания за 3-5 дней до консультации. Взять с собой результаты предыдущих обследований и анализов (при наличии).','active',0,'2026-04-21 11:53:30','2026-04-21 11:53:30'),(215,28,'Консультация психолога','konsultaciya-psihologa',74.98,30,'Консультация психолога — услуга, доступная в клинике с 1 сентября. Приём ведёт врач-психолог Петровская Татьяна Николаевна. Длительность консультации — 60 минут.\n\nПсихолог — специалист, изучающий способы и формы психологических проявлений личности в различных сферах деятельности человека.\n\nОсновные признаки, свидетельствующие о психическом расстройстве личности:\n• Низкая самооценка;\n• Чувство одиночества и безысходности;\n• Повышенная мрачность и раздражительность;\n• Отсутствие взаимопонимания.\n\nВрач-психолог проведет диагностику, составит план психологического консультирования и поможет оставаться здоровым без лекарств.\n\nМетодики, применяемые в диагностике:\n• Внимание и память: таблицы Шульте, счет по Крепелину, опосредованное запоминание по А.Н. Леонтьеву, заучивание 10 слов (А.Р. Лурия);\n• Мышление: классификация предметов, исключение четвертого лишнего, пиктограммы, ассоциативный эксперимент, соотношение пословиц и метафор;\n• Интеллект: тест Векслера, батарея лобных дисфункций (FAB), MMSE;\n• Личность: метод цветовых выборов Люшера, Миннесотский многофакторный метод, ПДО, незаконченные предложения, несуществующее животное, дом-дерево-человек;\n• Тревога, депрессия: шкала Бека, шкала Спилбергера, HADS;\n• Суицидальный риск: опросник суицидального риска, шкала безнадежности, шкала импульсивности.','• Низкая самооценка;\n• Чувство одиночества и безысходности;\n• Повышенная мрачность и раздражительность;\n• Отсутствие взаимопонимания с окружающими;\n• Тревожные состояния;\n• Признаки депрессии;\n• Эмоциональное выгорание;\n• Стрессовые ситуации.','Специальной подготовки не требуется.','active',0,'2026-04-21 11:54:26','2026-04-21 11:54:26'),(216,29,'Консультация врача-психотерапевта','konsultaciya-vracha-psihoterapevta',44.41,30,'Консультация психотерапевта проводится по предварительной записи. Врач-психотерапевт — это специалист с высшим медицинским образованием, который проводит лечение двумя способами:\n\nНемедикаментозный — с применением различных методов психотерапевтического воздействия (когнитивно-поведенческая психотерапия, эмоционально-рациональная психотерапия, гештальт-подход, эриксоновский гипноз и др.).\n\nС использованием лекарственных препаратов — ноотропов, витаминов, адаптогенов, антидепрессантов, нейролептиков. Лекарственная терапия является дополнительным методом, её эффективность минимальна, если пациент параллельно не прорабатывает причины психоэмоциональных проблем. В некоторых случаях препараты служат средством первой помощи для купирования острого состояния, после чего необходим курс психотерапии.\n\nКак проводится консультация:\n• Сбор жалоб с их детализацией;\n• Сбор анамнестических данных заболевания;\n• Выявление факторов риска заболеваний;\n• Интерпретация результатов исследований;\n• Проведение общего осмотра;\n• Установление клинико-функционального диагноза;\n• Определение тактики лечения и индивидуальных рекомендаций;\n• Назначение медикаментозного и немедикаментозного лечения;\n• Оформление медицинской документации и консультативного заключения.','• После сильного стресса, психологической травмы;\n• Подавленное настроение, потеря интереса к жизни, близким, работе;\n• Постоянная нервозность, тревожность, страхи;\n• Хроническая усталость, быстрая утомляемость даже после отдыха;\n• Нарушения сна: проблемы с засыпанием, чувство разбитости при пробуждении;\n• Вспыльчивость, раздражительность, перепады настроения;\n• Чувство эмоционального или профессионального выгорания;\n• Переедание, зависимость от алкоголя или азартных игр.','Специальной подготовки не требуется.\n\n','active',0,'2026-04-21 11:55:20','2026-04-21 11:55:20');
